+namespace Microsoft.Inventory.Test;
+
+using Microsoft.Inventory.Item;
+using Microsoft.Inventory.Journal;
+using Microsoft.Inventory.Location;
+using Microsoft.Manufacturing.Document;
+using Microsoft.Manufacturing.ProductionBOM;
+using Microsoft.Warehouse.Activity;
+using Microsoft.Warehouse.Request;
+using Microsoft.Warehouse.Setup;
+using Microsoft.Warehouse.Structure;
+using Microsoft.Warehouse.Worksheet;
+using System.TestLibraries.Utilities;
+
+codeunit 137505 "SCM Pick Worksheet Availability"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Warehouse] [Pick Worksheet] [Availability] [Production] [SCM]
+        IsInitialized := false;
+    end;
+
+    var
+        ItemJournalTemplate: Record "Item Journal Template";
+        ItemJournalBatch: Record "Item Journal Batch";
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibrarySetupStorage: Codeunit "Library - Setup Storage";
+        LibraryWarehouse: Codeunit "Library - Warehouse";
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryManufacturing: Codeunit "Library - Manufacturing";
+        LibraryUtility: Codeunit "Library - Utility";
+        IsInitialized: Boolean;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure CreatePickFromWorksheetWithReservedProdOrderComponentsAtBinMandatoryLocation()
+    var
+        ComponentItem: Record Item;
+        ParentItem: Record Item;
+        Location: Record Location;
+        Bin: Record Bin;
+        ProductionOrder1: Record "Production Order";
+        ProductionOrder2: Record "Production Order";
+        ProdOrderComponent1: Record "Prod. Order Component";
+        ProdOrderComponent2: Record "Prod. Order Component";
+        WhseWorksheetLine: Record "Whse. Worksheet Line";
+        WhseWorksheetName: Record "Whse. Worksheet Name";
+        WhseWorksheetTemplate: Record "Whse. Worksheet Template";
+        WhsePickRequest: Record "Whse. Pick Request";
+        WarehouseActivityLine: Record "Warehouse Activity Line";
+        ProductionBOMHeader: Record "Production BOM Header";
+        ComponentQtyPer: Decimal;
+        TotalInventory: Decimal;
+        Qty1: Decimal;
+        Qty2: Decimal;
+    begin
+        // [FEATURE] [Pick Worksheet] [Production Order] [Reservation]
+        // [SCENARIO] Creating picks from pick worksheet should succeed when production order components are reserved
+        // at a location with Bin Mandatory = true and Prod. Consump. Whse. Handling = Warehouse Pick (mandatory)
+        Initialize();
+        ComponentQtyPer := 1;
+        Qty1 := 2;
+        Qty2 := 1;
+        TotalInventory := (Qty1 + Qty2) * ComponentQtyPer;
+
+        // [GIVEN] Create Location with Bin Mandatory and Prod. Consump. Whse. Handling = Warehouse Pick (mandatory)
+        CreateLocationWithBinMandatoryAndWhsePickMandatory(Location);
+        LibraryWarehouse.CreateBin(Bin, Location.Code, LibraryUtility.GenerateGUID(), '', '');
+
+        // [GIVEN] Create component item and production item with BOM
+        LibraryInventory.CreateItem(ComponentItem);
+        LibraryInventory.CreateItem(ParentItem);
+        LibraryManufacturing.CreateCertifiedProductionBOM(ProductionBOMHeader, ComponentItem."No.", ComponentQtyPer);
+        ParentItem.Validate("Production BOM No.", ProductionBOMHeader."No.");
+        ParentItem.Validate("Replenishment System", ParentItem."Replenishment System"::"Prod. Order");
+        ParentItem.Modify(true);
+
+        // [GIVEN] Post inventory of component item to location with bin
+        CreateAndPostItemJournalLine(ComponentItem."No.", TotalInventory, Location.Code, Bin.Code);
+
+        // [GIVEN] Create first released production order for quantity 2
+        CreateAndRefreshProductionOrder(ProductionOrder1, ParentItem."No.", Qty1, Location.Code);
+
+        // [GIVEN] Create second released production order for quantity 1
+        CreateAndRefreshProductionOrder(ProductionOrder2, ParentItem."No.", Qty2, Location.Code);
+
+        // [GIVEN] Reserve component in first production order
+        FindProdOrderComponent(ProdOrderComponent1, ProductionOrder1);
+        ProdOrderComponent1.AutoReserve();
+
+        // [GIVEN] Reserve component in second production order
+        FindProdOrderComponent(ProdOrderComponent2, ProductionOrder2);
+        ProdOrderComponent2.AutoReserve();
+
+        // [GIVEN] Get pick worksheet template and name
+        GetPickWorksheetTemplate(WhseWorksheetTemplate);
+        CreatePickWorksheetName(WhseWorksheetName, WhseWorksheetTemplate.Name, Location.Code);
+
+        // [GIVEN] Get warehouse documents for both production orders into pick worksheet
+        WhsePickRequest.SetRange("Document Type", WhsePickRequest."Document Type"::Production);
+        WhsePickRequest.SetRange("Location Code", Location.Code);
+        WhsePickRequest.SetRange("Completely Picked", false);
+        LibraryWarehouse.GetOutboundSourceDocuments(WhsePickRequest, WhseWorksheetName, Location.Code);
+
+        // [GIVEN] Verify pick worksheet lines are created
+        WhseWorksheetLine.SetRange("Worksheet Template Name", WhseWorksheetTemplate.Name);
+        WhseWorksheetLine.SetRange(Name, WhseWorksheetName.Name);
+        WhseWorksheetLine.SetRange("Location Code", Location.Code);
+        Assert.RecordCount(WhseWorksheetLine, 2);
+
+        // [WHEN] Create pick from pick worksheet for all lines
+        WhseWorksheetLine.FindSet();
+        repeat
+            // [THEN] No error occurs when creating pick - the availability is correctly calculated considering reservations
+            CreatePickFromWorksheetLine(WhseWorksheetLine);
+        until WhseWorksheetLine.Next() = 0;
+
+        // [THEN] Pick lines are created for the production order components
+        WarehouseActivityLine.SetRange("Activity Type", WarehouseActivityLine."Activity Type"::Pick);
+        WarehouseActivityLine.SetRange("Location Code", Location.Code);
+        WarehouseActivityLine.SetRange("Item No.", ComponentItem."No.");
+        Assert.RecordIsNotEmpty(WarehouseActivityLine);
+    end;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure AvailQtyToPickWithReservedComponentsAtBinMandatoryLocationWithWhsePickMandatory()
+    var
+        ComponentItem: Record Item;
+        ParentItem: Record Item;
+        Location: Record Location;
+        Bin: Record Bin;
+        ProductionOrder1: Record "Production Order";
+        ProductionOrder2: Record "Production Order";
+        ProdOrderComponent1: Record "Prod. Order Component";
+        ProdOrderComponent2: Record "Prod. Order Component";
+        WhseWorksheetLine: Record "Whse. Worksheet Line";
+        WhseWorksheetName: Record "Whse. Worksheet Name";
+        WhseWorksheetTemplate: Record "Whse. Worksheet Template";
+        WhsePickRequest: Record "Whse. Pick Request";
+        ProductionBOMHeader: Record "Production BOM Header";
+        ComponentQtyPer: Decimal;
+        TotalInventory: Decimal;
+        Qty1: Decimal;
+        Qty2: Decimal;
+        AvailableQty: Decimal;
+    begin
+        // [FEATURE] [Pick Worksheet] [Production Order] [Reservation] [UT]
+        // [SCENARIO] AvailableQtyToPick should return correct quantity when components are reserved
+        // at a location with Bin Mandatory = true and Prod. Consump. Whse. Handling = Warehouse Pick (mandatory)
+        Initialize();
+        ComponentQtyPer := 1;
+        Qty1 := 2;
+        Qty2 := 1;
+        TotalInventory := (Qty1 + Qty2) * ComponentQtyPer;
+
+        // [GIVEN] Create Location with Bin Mandatory and Prod. Consump. Whse. Handling = Warehouse Pick (mandatory)
+        CreateLocationWithBinMandatoryAndWhsePickMandatory(Location);
+        LibraryWarehouse.CreateBin(Bin, Location.Code, LibraryUtility.GenerateGUID(), '', '');
+
+        // [GIVEN] Create component item and production item with BOM
+        LibraryInventory.CreateItem(ComponentItem);
+        LibraryInventory.CreateItem(ParentItem);
+        LibraryManufacturing.CreateCertifiedProductionBOM(ProductionBOMHeader, ComponentItem."No.", ComponentQtyPer);
+        ParentItem.Validate("Production BOM No.", ProductionBOMHeader."No.");
+        ParentItem.Validate("Replenishment System", ParentItem."Replenishment System"::"Prod. Order");
+        ParentItem.Modify(true);
+
+        // [GIVEN] Post inventory of component item to location with bin
+        CreateAndPostItemJournalLine(ComponentItem."No.", TotalInventory, Location.Code, Bin.Code);
+
+        // [GIVEN] Create first released production order for quantity 2
+        CreateAndRefreshProductionOrder(ProductionOrder1, ParentItem."No.", Qty1, Location.Code);
+
+        // [GIVEN] Create second released production order for quantity 1
+        CreateAndRefreshProductionOrder(ProductionOrder2, ParentItem."No.", Qty2, Location.Code);
+
+        // [GIVEN] Reserve component in first production order
+        FindProdOrderComponent(ProdOrderComponent1, ProductionOrder1);
+        ProdOrderComponent1.AutoReserve();
+
+        // [GIVEN] Reserve component in second production order
+        FindProdOrderComponent(ProdOrderComponent2, ProductionOrder2);
+        ProdOrderComponent2.AutoReserve();
+
+        // [GIVEN] Get pick worksheet template and name
+        GetPickWorksheetTemplate(WhseWorksheetTemplate);
+        CreatePickWorksheetName(WhseWorksheetName, WhseWorksheetTemplate.Name, Location.Code);
+
+        // [WHEN] Get warehouse documents for production orders into pick worksheet
+        WhsePickRequest.SetRange("Document Type", WhsePickRequest."Document Type"::Production);
+        WhsePickRequest.SetRange("Location Code", Location.Code);
+        WhsePickRequest.SetRange("Completely Picked", false);
+        LibraryWarehouse.GetOutboundSourceDocuments(WhsePickRequest, WhseWorksheetName, Location.Code);
+
+        // [THEN] Pick worksheet lines have correct available quantity to pick (considering reservations)
+        WhseWorksheetLine.SetRange("Worksheet Template Name", WhseWorksheetTemplate.Name);
+        WhseWorksheetLine.SetRange(Name, WhseWorksheetName.Name);
+        WhseWorksheetLine.SetRange("Location Code", Location.Code);
+        WhseWorksheetLine.FindSet();
+        repeat
+            AvailableQty := WhseWorksheetLine.AvailableQtyToPick();
+            // Available quantity should be at least equal to the line quantity because reservations are from the same source
+            Assert.IsTrue(AvailableQty >= WhseWorksheetLine."Qty. to Handle",
+                StrSubstNo('Available Qty. to Pick (%1) should be >= Qty. to Handle (%2) for Line No. %3',
+                    AvailableQty, WhseWorksheetLine."Qty. to Handle", WhseWorksheetLine."Line No."));
+        until WhseWorksheetLine.Next() = 0;
+    end;
+
+    local procedure Initialize()
+    var
+        WarehouseSetup: Record "Warehouse Setup";
+        InventorySetup: Record "Inventory Setup";
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"SCM Pick Worksheet Availability");
+        LibrarySetupStorage.Restore();
+
+        if IsInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"SCM Pick Worksheet Availability");
+
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        LibraryERMCountryData.UpdateVATPostingSetup();
+        LibraryERMCountryData.CreateVATData();
+
+        LibraryWarehouse.NoSeriesSetup(WarehouseSetup);
+        LibraryInventory.NoSeriesSetup(InventorySetup);
+
+        ItemJournalSetup();
+
+        IsInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"SCM Pick Worksheet Availability");
+    end;
+
+    local procedure ItemJournalSetup()
+    begin
+        LibraryInventory.SelectItemJournalTemplateName(ItemJournalTemplate, ItemJournalTemplate.Type::Item);
+        ItemJournalTemplate.Validate("No. Series", LibraryUtility.GetGlobalNoSeriesCode());
+        ItemJournalTemplate.Modify(true);
+
+        LibraryInventory.SelectItemJournalBatchName(ItemJournalBatch, ItemJournalTemplate.Type, ItemJournalTemplate.Name);
+        ItemJournalBatch.Validate("No. Series", LibraryUtility.GetGlobalNoSeriesCode());
+        ItemJournalBatch.Modify(true);
+    end;
+
+    local procedure CreateLocationWithBinMandatoryAndWhsePickMandatory(var Location: Record Location)
+    var
+        WarehouseEmployee: Record "Warehouse Employee";
+    begin
+        // Create location with Bin Mandatory = true, but Require Pick = false
+        // This is the key scenario - Prod. Consump. Whse. Handling = Warehouse Pick (mandatory) without Require Pick
+        LibraryWarehouse.CreateLocationWithInventoryPostingSetup(Location);
+        Location.Validate("Bin Mandatory", true);
+        Location.Validate("Require Pick", false);
+        Location.Validate("Require Shipment", false);
+        Location.Validate("Prod. Consump. Whse. Handling", Location."Prod. Consump. Whse. Handling"::"Warehouse Pick (mandatory)");
+        Location.Modify(true);
+
+        LibraryWarehouse.CreateWarehouseEmployee(WarehouseEmployee, Location.Code, true);
+    end;
+
+    local procedure CreateAndPostItemJournalLine(ItemNo: Code[20]; Quantity: Decimal; LocationCode: Code[10]; BinCode: Code[20])
+    var
+        ItemJournalLine: Record "Item Journal Line";
+    begin
+        LibraryInventory.ClearItemJournal(ItemJournalTemplate, ItemJournalBatch);
+        LibraryInventory.CreateItemJournalLine(
+            ItemJournalLine, ItemJournalTemplate.Name, ItemJournalBatch.Name,
+            ItemJournalLine."Entry Type"::"Positive Adjmt.", ItemNo, Quantity);
+        ItemJournalLine.Validate("Location Code", LocationCode);
+        if BinCode <> '' then
+            ItemJournalLine.Validate("Bin Code", BinCode);
+        ItemJournalLine.Modify(true);
+        LibraryInventory.PostItemJournalLine(ItemJournalTemplate.Name, ItemJournalBatch.Name);
+    end;
+
+    local procedure CreateAndRefreshProductionOrder(var ProductionOrder: Record "Production Order"; ItemNo: Code[20]; Quantity: Decimal; LocationCode: Code[10])
+    begin
+        LibraryManufacturing.CreateProductionOrder(
+            ProductionOrder, ProductionOrder.Status::Released,
+            ProductionOrder."Source Type"::Item, ItemNo, Quantity);
+        ProductionOrder.Validate("Location Code", LocationCode);
+        ProductionOrder.Modify(true);
+        LibraryManufacturing.RefreshProdOrder(ProductionOrder, false, true, true, true, false);
+    end;
+
+    local procedure FindProdOrderComponent(var ProdOrderComponent: Record "Prod. Order Component"; ProductionOrder: Record "Production Order")
+    begin
+        ProdOrderComponent.SetRange(Status, ProductionOrder.Status);
+        ProdOrderComponent.SetRange("Prod. Order No.", ProductionOrder."No.");
+        ProdOrderComponent.FindFirst();
+    end;
+
+    local procedure GetPickWorksheetTemplate(var WhseWorksheetTemplate: Record "Whse. Worksheet Template")
+    begin
+        WhseWorksheetTemplate.SetRange(Type, WhseWorksheetTemplate.Type::Pick);
+        WhseWorksheetTemplate.FindFirst();
+    end;
+
+    local procedure CreatePickWorksheetName(var WhseWorksheetName: Record "Whse. Worksheet Name"; TemplateName: Code[10]; LocationCode: Code[10])
+    begin
+        if not WhseWorksheetName.Get(TemplateName, LibraryUtility.GenerateGUID(), LocationCode) then begin
+            WhseWorksheetName.Init();
+            WhseWorksheetName.Validate("Worksheet Template Name", TemplateName);
+            WhseWorksheetName.Validate(Name, LibraryUtility.GenerateGUID());
+            WhseWorksheetName.Validate("Location Code", LocationCode);
+            WhseWorksheetName.Insert(true);
+        end;
+    end;
+
+    local procedure CreatePickFromWorksheetLine(var WhseWorksheetLine: Record "Whse. Worksheet Line")
+    var
+        WhseWorksheetLine2: Record "Whse. Worksheet Line";
+        CreatePick: Report "Create Pick";
+    begin
+        WhseWorksheetLine2 := WhseWorksheetLine;
+        WhseWorksheetLine2.SetRecFilter();
+
+        CreatePick.InitializeReport(
+            '', 0, 0, "Whse. Activity Sorting Method"::None,
+            false, false, false, false, false, false, false, false, false);
+        CreatePick.UseRequestPage(false);
+        CreatePick.SetWkshPickLine(WhseWorksheetLine2);
+        CreatePick.RunModal();
+        Clear(CreatePick);
+    end;
+}

diff --git a/App/Layers/W1/Tests/ERM/ERMPurchJnlDocAmountDecimal.Codeunit.al b/App/Layers/W1/Tests/ERM/ERMPurchJnlDocAmountDecimal.Codeunit.al
