+++ b/App/Layers/W1/Tests/ERM/ERMPurchJnlDocAmountDecimal.Codeunit.al
@@ -0,0 +1,87 @@
+codeunit 134999 "ERM Purch Jnl Doc Amt Decimal"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Purchase Journal] [Document Amount] [Currency]
+        isInitialized := false;
+    end;
+
+    var
+        LibraryERM: Codeunit "Library - ERM";
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        isInitialized: Boolean;
+        DocumentAmountDecimalErr: Label 'The document amount should accept %1 decimal places.';
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure PurchaseJournalDocumentAmountAcceptsThreeDecimalPlaces()
+    var
+        Currency: Record Currency;
+        PurchaseJournal: TestPage "Purchase Journal";
+        ExpectedAmount: Decimal;
+    begin
+        // [SCENARIO] Document Amount field in Purchase Journal accepts amounts with 3 decimal places for currencies like TND
+        // [FEATURE] [Purchase Journal] [Document Amount] [Currency Decimal Places]
+
+        // [GIVEN] Standard initialization
+        Initialize();
+
+        // [GIVEN] A currency with 3 decimal places (like TND - Tunisian Dinar)
+        CreateCurrencyWithThreeDecimalPlaces(Currency);
+
+        // [WHEN] Purchase Journal is opened and Document Amount is set with 3 decimal places
+        PurchaseJournal.OpenEdit();
+        PurchaseJournal.New();
+        PurchaseJournal."Currency Code".SetValue(Currency.Code);
+
+        // [THEN] Document Amount field accepts value with 3 decimal places without error
+        ExpectedAmount := 1.234;
+        PurchaseJournal.DocumentAmount.SetValue(ExpectedAmount);
+
+        // Verify the value was accepted correctly by checking the Amount field (which should be -1.234 for Invoice)
+        Assert.AreEqual(
+            Format(-ExpectedAmount),
+            PurchaseJournal.Amount.Value,
+            StrSubstNo(DocumentAmountDecimalErr, 3));
+
+        PurchaseJournal.Close();
+    end;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+        GenJnlManagement: Codeunit "GenJnlManagement";
+    begin
+        LibraryTestInitialize.OnTestInitialize(CODEUNIT::"ERM Purch Jnl Doc Amt Decimal");
+
+        if isInitialized then
+            exit;
+
+        GenJnlManagement.SetJournalSimplePageModePreference(true, Page::"Purchase Journal");
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(CODEUNIT::"ERM Purch Jnl Doc Amt Decimal");
+
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdateAccountInVendorPostingGroups();
+        LibraryERMCountryData.RemoveBlankGenJournalTemplate();
+        LibraryERMCountryData.UpdateGeneralLedgerSetup();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+
+        isInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(CODEUNIT::"ERM Purch Jnl Doc Amt Decimal");
+    end;
+
+    local procedure CreateCurrencyWithThreeDecimalPlaces(var Currency: Record Currency)
+    begin
+        // Create a currency similar to TND (Tunisian Dinar) which uses 3 decimal places
+        LibraryERM.CreateCurrency(Currency);
+        Currency.Validate("Amount Decimal Places", '0:3');
+        Currency.Validate("Amount Rounding Precision", 0.001);
+        Currency.Modify(true);
+        LibraryERM.CreateRandomExchangeRate(Currency.Code);
+    end;
+}

diff --git a/App/Layers/W1/Tests/ERM/PriceListLinesVariantCodeTest.Codeunit.al b/App/Layers/W1/Tests/ERM/PriceListLinesVariantCodeTest.Codeunit.al
new file mode 100644
index 00000000..a7ed28d3
--- /dev/null
+++ b/App/Layers/W1/Tests/ERM/PriceListLinesVariantCodeTest.Codeunit.al
@@ -0,0 +1,107 @@
+codeunit 134999 "Price List Lines Variant Code"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Price Calculation] [Price List] [Variant Code]
+    end;
+
+    var
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryPriceCalculation: Codeunit "Library - Price Calculation";
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+
+    [Test]
+    procedure NewSalesPriceListLineDoesNotInheritVariantCode()
+    var
+        Item: Record Item;
+        ItemVariant: Record "Item Variant";
+        PriceListHeader: Record "Price List Header";
+        PriceListLine: Record "Price List Line";
+        SalesPriceList: TestPage "Sales Price List";
+    begin
+        // [FEATURE] [Sales] [Item] [Variant]
+        // [SCENARIO] When creating a new price list line, the variant code should not be preset from the previous line
+        Initialize();
+
+        // [GIVEN] Item 'X' with Variant 'V'
+        LibraryInventory.CreateItem(Item);
+        LibraryInventory.CreateItemVariant(ItemVariant, Item."No.");
+
+        // [GIVEN] Sales Price list with one line for Item 'X' with Variant 'V'
+        LibraryPriceCalculation.CreatePriceHeader(PriceListHeader, "Price Type"::Sale, "Price Source Type"::"All Customers", '');
+        LibraryPriceCalculation.CreateSalesPriceLine(
+            PriceListLine, PriceListHeader.Code, "Price Source Type"::"All Customers", '', "Price Asset Type"::Item, Item."No.");
+        PriceListLine.Validate("Variant Code", ItemVariant.Code);
+        PriceListLine.Modify(true);
+
+        // [GIVEN] Open Sales Price List page with the price list
+        SalesPriceList.OpenEdit();
+        SalesPriceList.Filter.SetFilter(Code, PriceListHeader.Code);
+
+        // [WHEN] Add a new line with Asset Type Item
+        SalesPriceList.Lines.New();
+        SalesPriceList.Lines."Asset Type".SetValue("Price Asset Type"::Item);
+
+        // [THEN] Variant Code is blank on the new line (not inherited from previous line)
+        SalesPriceList.Lines."Variant Code".AssertEquals('');
+
+        SalesPriceList.Close();
+    end;
+
+    [Test]
+    procedure NewPurchasePriceListLineDoesNotInheritVariantCode()
+    var
+        Item: Record Item;
+        ItemVariant: Record "Item Variant";
+        PriceListHeader: Record "Price List Header";
+        PriceListLine: Record "Price List Line";
+        PurchasePriceList: TestPage "Purchase Price List";
+    begin
+        // [FEATURE] [Purchase] [Item] [Variant]
+        // [SCENARIO] When creating a new purchase price list line, the variant code should not be preset from the previous line
+        Initialize();
+
+        // [GIVEN] Item 'X' with Variant 'V'
+        LibraryInventory.CreateItem(Item);
+        LibraryInventory.CreateItemVariant(ItemVariant, Item."No.");
+
+        // [GIVEN] Purchase Price list with one line for Item 'X' with Variant 'V'
+        LibraryPriceCalculation.CreatePriceHeader(PriceListHeader, "Price Type"::Purchase, "Price Source Type"::"All Vendors", '');
+        LibraryPriceCalculation.CreatePurchPriceLine(
+            PriceListLine, PriceListHeader.Code, "Price Source Type"::"All Vendors", '', "Price Asset Type"::Item, Item."No.");
+        PriceListLine.Validate("Variant Code", ItemVariant.Code);
+        PriceListLine.Modify(true);
+
+        // [GIVEN] Open Purchase Price List page with the price list
+        PurchasePriceList.OpenEdit();
+        PurchasePriceList.Filter.SetFilter(Code, PriceListHeader.Code);
+
+        // [WHEN] Add a new line with Asset Type Item
+        PurchasePriceList.Lines.New();
+        PurchasePriceList.Lines."Asset Type".SetValue("Price Asset Type"::Item);
+
+        // [THEN] Variant Code is blank on the new line (not inherited from previous line)
+        PurchasePriceList.Lines."Variant Code".AssertEquals('');
+
+        PurchasePriceList.Close();
+    end;
+
+    local procedure Initialize()
+    var
+        PriceListHeader: Record "Price List Header";
+        PriceListLine: Record "Price List Line";
+    begin
+        LibraryTestInitialize.OnTestInitialize(CODEUNIT::"Price List Lines Variant Code");
+
+        LibraryPriceCalculation.EnableExtendedPriceCalculation(true);
+        LibraryPriceCalculation.SetUseCustomLookup(true);
+
+        PriceListHeader.ModifyAll(Status, PriceListHeader.Status::Draft);
+        PriceListHeader.DeleteAll(true);
+        PriceListLine.ModifyAll(Status, PriceListLine.Status::Draft);
+        PriceListLine.DeleteAll(true);
+    end;
+}

diff --git a/App/Layers/W1/Tests/SCM/SCMInvtPickInvDiscount.Codeunit.al b/App/Layers/W1/Tests/SCM/SCMInvtPickInvDiscount.Codeunit.al
