@@ -0,0 +1,191 @@
+codeunit 134779 "SCM Invt. Pick Inv. Discount"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Inventory Pick] [Invoice Discount] [Currency]
+    end;
+
+    var
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryRandom: Codeunit "Library - Random";
+        LibraryUtility: Codeunit "Library - Utility";
+        LibrarySetupStorage: Codeunit "Library - Setup Storage";
+        LibraryWarehouse: Codeunit "Library - Warehouse";
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryERM: Codeunit "Library - ERM";
+        IsInitialized: Boolean;
+
+    [Test]
+    [HandlerFunctions('MessageHandler,CreateInvtPickRequestPageHandler,ConfirmHandlerYes')]
+    [Scope('OnPrem')]
+    procedure InvoiceDiscountPreservedWhenPostingInvtPickWithDifferentPostingDate()
+    var
+        Location: Record Location;
+        Bin: Record Bin;
+        Item: Record Item;
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        WarehouseActivityHeader: Record "Warehouse Activity Header";
+        WarehouseActivityLine: Record "Warehouse Activity Line";
+        SalesCalcDiscountByType: Codeunit "Sales - Calc Discount By Type";
+        CurrencyCode: Code[10];
+        InvDiscountPercent: Decimal;
+        OriginalPostingDate: Date;
+        NewPostingDate: Date;
+        ExpectedInvDiscAmount: Decimal;
+    begin
+        // [FEATURE] [Invoice Discount] [Sales] [Order] [Inventory Pick] [Currency]
+        // [SCENARIO 537530] Invoice discount is preserved when posting inventory pick with a new posting date that causes currency factor update.
+        Initialize();
+        InvDiscountPercent := LibraryRandom.RandIntInRange(30, 70);
+        OriginalPostingDate := WorkDate();
+        NewPostingDate := WorkDate() + 30;
+
+        // [GIVEN] Currency Code "ACY" with two different exchange rates on dates "D1" and "D2".
+        CurrencyCode :=
+          LibraryERM.CreateCurrencyWithExchangeRate(
+            OriginalPostingDate, LibraryRandom.RandDecInRange(51, 100, 2), LibraryRandom.RandDecInRange(51, 100, 2));
+        LibraryERM.CreateExchangeRate(
+          CurrencyCode, NewPostingDate, LibraryRandom.RandDec(50, 2), LibraryRandom.RandDec(50, 2));
+
+        // [GIVEN] Location "L" with Require Pick = true and Bin Mandatory = true.
+        CreateLocationWithBin(Location, Bin);
+
+        // [GIVEN] Create an item and update inventory on the location "L".
+        LibraryInventory.CreateItem(Item);
+        CreateAndPostItemJournalLine(Item."No.", LibraryRandom.RandIntInRange(20, 40), Location.Code, Bin.Code);
+
+        // [GIVEN] Create sales order with Posting Date = "D1".
+        // [GIVEN] Set Currency Code = "ACY" and apply invoice discount = 30%.
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Order, '');
+        SalesHeader.Validate("Location Code", Location.Code);
+        SalesHeader.Validate("Currency Code", CurrencyCode);
+        SalesHeader.Modify(true);
+
+        LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::Item, Item."No.", LibraryRandom.RandInt(10));
+        SalesLine.Validate("Location Code", Location.Code);
+        SalesLine.Validate("Bin Code", Bin.Code);
+        SalesLine.Validate("Unit Price", LibraryRandom.RandDecInRange(100, 1000, 2));
+        SalesLine.Modify(true);
+
+        // Apply invoice discount
+        ExpectedInvDiscAmount := SalesLine."Line Amount" * InvDiscountPercent / 100;
+        SalesCalcDiscountByType.ApplyInvDiscBasedOnAmt(ExpectedInvDiscAmount, SalesHeader);
+
+        // Refresh sales line to get the applied invoice discount
+        SalesLine.Find();
+        ExpectedInvDiscAmount := SalesLine."Inv. Discount Amount";
+        Assert.AreNotEqual(0, ExpectedInvDiscAmount, 'Invoice discount should be applied');
+
+        // [GIVEN] Release the sales order and create inventory pick.
+        LibrarySales.ReleaseSalesDocument(SalesHeader);
+        Commit();
+        SalesHeader.CreateInvtPutAwayPick();
+
+        // [GIVEN] Set posting date = "D2" on the inventory pick (different date with different exchange rate).
+        FindWarehouseActivityLine(WarehouseActivityLine, DATABASE::"Sales Line", SalesHeader."No.", WarehouseActivityHeader.Type::"Invt. Pick");
+        WarehouseActivityHeader.Get(WarehouseActivityHeader.Type::"Invt. Pick", WarehouseActivityLine."No.");
+        WarehouseActivityHeader.Validate("Posting Date", NewPostingDate);
+        WarehouseActivityHeader.Modify(true);
+        LibraryWarehouse.SetQtyToHandleWhseActivity(WarehouseActivityHeader, WarehouseActivityLine.Quantity);
+
+        // [WHEN] Post the inventory pick (Ship).
+        LibraryWarehouse.PostInventoryActivity(WarehouseActivityHeader, false);
+
+        // [THEN] The invoice discount on the sales line is preserved.
+        SalesLine.Find();
+        Assert.AreNearlyEqual(
+          ExpectedInvDiscAmount, SalesLine."Inv. Discount Amount",
+          LibraryERM.GetCurrencyAmountRoundingPrecision(CurrencyCode),
+          'Invoice discount should be preserved after posting inventory pick with different posting date');
+    end;
+
+    local procedure Initialize()
+    var
+        WarehouseEmployee: Record "Warehouse Employee";
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(CODEUNIT::"SCM Invt. Pick Inv. Discount");
+        LibrarySetupStorage.Restore();
+        WarehouseEmployee.DeleteAll();
+        if IsInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(CODEUNIT::"SCM Invt. Pick Inv. Discount");
+
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdatePurchasesPayablesSetup();
+        LibraryERMCountryData.UpdateSalesReceivablesSetup();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        LibraryERMCountryData.UpdateLocalData();
+        LibraryERMCountryData.UpdateJournalTemplMandatory(false);
+        LibrarySetupStorage.Save(DATABASE::"Sales & Receivables Setup");
+        LibrarySetupStorage.Save(DATABASE::"Purchases & Payables Setup");
+        LibrarySetupStorage.Save(DATABASE::"General Ledger Setup");
+
+        IsInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(CODEUNIT::"SCM Invt. Pick Inv. Discount");
+    end;
+
+    local procedure CreateLocationWithBin(var Location: Record Location; var Bin: Record Bin)
+    var
+        WarehouseEmployee: Record "Warehouse Employee";
+    begin
+        // Create location with Require Pick and Bin Mandatory (like SILVER location in repro steps)
+        LibraryWarehouse.CreateLocationWMS(Location, true, false, true, false, false);
+        LibraryWarehouse.CreateWarehouseEmployee(WarehouseEmployee, Location.Code, true);
+
+        LibraryWarehouse.CreateBin(
+            Bin, Location.Code,
+            CopyStr(
+                LibraryUtility.GenerateRandomCode(Bin.FieldNo(Code), DATABASE::Bin), 1,
+                LibraryUtility.GetFieldLength(DATABASE::Bin, Bin.FieldNo(Code))), '', '');
+        Location.Validate("Default Bin Code", Bin.Code);
+        Location.Modify(true);
+    end;
+
+    local procedure CreateAndPostItemJournalLine(ItemNo: Code[20]; Quantity: Decimal; LocationCode: Code[10]; BinCode: Code[20])
+    var
+        ItemJournalLine: Record "Item Journal Line";
+    begin
+        LibraryInventory.CreateItemJournalLineInItemTemplate(
+            ItemJournalLine, ItemNo, LocationCode, BinCode, Quantity);
+        LibraryInventory.PostItemJournalLine(
+            ItemJournalLine."Journal Template Name", ItemJournalLine."Journal Batch Name");
+    end;
+
+    local procedure FindWarehouseActivityLine(var WarehouseActivityLine: Record "Warehouse Activity Line"; SourceType: Integer; SourceNo: Code[20]; ActivityType: Enum "Warehouse Activity Type")
+    begin
+        WarehouseActivityLine.SetRange("Source Type", SourceType);
+        WarehouseActivityLine.SetRange("Source No.", SourceNo);
+        WarehouseActivityLine.SetRange("Activity Type", ActivityType);
+        WarehouseActivityLine.FindFirst();
+    end;
+
+    [RequestPageHandler]
+    [Scope('OnPrem')]
+    procedure CreateInvtPickRequestPageHandler(var CreateInvtPutawayPickMvmt: TestRequestPage "Create Invt Put-away/Pick/Mvmt")
+    begin
+        CreateInvtPutawayPickMvmt.CInvtPick.SetValue(true);
+        CreateInvtPutawayPickMvmt.OK().Invoke();
+    end;
+
+    [ConfirmHandler]
+    [Scope('OnPrem')]
+    procedure ConfirmHandlerYes(Question: Text[1024]; var Reply: Boolean)
+    begin
+        Reply := true;
+    end;
+
+    [MessageHandler]
+    [Scope('OnPrem')]
+    procedure MessageHandler(Message: Text[1024])
+    begin
+        // Message Handler - suppress messages.
+    end;
+}

