+codeunit 148188 "Sust. Setup Value Chain Test"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    var
+        Assert: Codeunit Assert;
+
+    [Test]
+    [HandlerFunctions('ConfirmHandlerYes')]
+    procedure EnablingValueChainTrackingEnablesRelatedEmissionsFields()
+    var
+        SustainabilitySetup: Record "Sustainability Setup";
+    begin
+        // [SCENARIO] Verify enabling 'Enable Value Chain Tracking' also enables related emissions fields:
+        // - Use Emissions In Purchase Documents
+        // - Item Emissions
+        // - Resource Emissions
+        // - Work/Machine Center Emissions
+
+        // [GIVEN] A Sustainability Setup record with all Procurement FastTab fields disabled
+        if not SustainabilitySetup.Get() then
+            SustainabilitySetup.Insert();
+
+        SustainabilitySetup."Use Emissions In Purch. Doc." := false;
+        SustainabilitySetup."Item Emissions" := false;
+        SustainabilitySetup."Resource Emissions" := false;
+        SustainabilitySetup."Work/Machine Center Emissions" := false;
+        SustainabilitySetup."Enable Value Chain Tracking" := false;
+        SustainabilitySetup.Modify();
+
+        // [WHEN] Enabling 'Enable Value Chain Tracking'
+        SustainabilitySetup.Validate("Enable Value Chain Tracking", true);
+
+        // [THEN] Verify that 'Use Emissions In Purch. Doc.' is enabled
+        Assert.IsTrue(
+            SustainabilitySetup."Use Emissions In Purch. Doc.",
+            'Use Emissions In Purch. Doc. should be enabled when Enable Value Chain Tracking is enabled');
+
+        // [THEN] Verify that 'Item Emissions' is enabled
+        Assert.IsTrue(
+            SustainabilitySetup."Item Emissions",
+            'Item Emissions should be enabled when Enable Value Chain Tracking is enabled');
+
+        // [THEN] Verify that 'Resource Emissions' is enabled
+        Assert.IsTrue(
+            SustainabilitySetup."Resource Emissions",
+            'Resource Emissions should be enabled when Enable Value Chain Tracking is enabled');
+
+        // [THEN] Verify that 'Work/Machine Center Emissions' is enabled
+        Assert.IsTrue(
+            SustainabilitySetup."Work/Machine Center Emissions",
+            'Work/Machine Center Emissions should be enabled when Enable Value Chain Tracking is enabled');
+    end;
+
+    [Test]
+    [HandlerFunctions('ConfirmHandlerYes')]
+    procedure EnablingValueChainTrackingPreservesAlreadyEnabledEmissionsFields()
+    var
+        SustainabilitySetup: Record "Sustainability Setup";
+    begin
+        // [SCENARIO] Verify enabling 'Enable Value Chain Tracking' preserves already enabled emissions fields
+
+        // [GIVEN] A Sustainability Setup record with some emissions fields already enabled
+        if not SustainabilitySetup.Get() then
+            SustainabilitySetup.Insert();
+
+        SustainabilitySetup."Use Emissions In Purch. Doc." := true;
+        SustainabilitySetup."Item Emissions" := true;
+        SustainabilitySetup."Resource Emissions" := false;
+        SustainabilitySetup."Work/Machine Center Emissions" := false;
+        SustainabilitySetup."Enable Value Chain Tracking" := false;
+        SustainabilitySetup.Modify();
+
+        // [WHEN] Enabling 'Enable Value Chain Tracking'
+        SustainabilitySetup.Validate("Enable Value Chain Tracking", true);
+
+        // [THEN] Verify all emissions fields are enabled
+        Assert.IsTrue(
+            SustainabilitySetup."Use Emissions In Purch. Doc.",
+            'Use Emissions In Purch. Doc. should remain enabled');
+
+        Assert.IsTrue(
+            SustainabilitySetup."Item Emissions",
+            'Item Emissions should remain enabled');
+
+        Assert.IsTrue(
+            SustainabilitySetup."Resource Emissions",
+            'Resource Emissions should be enabled when Enable Value Chain Tracking is enabled');
+
+        Assert.IsTrue(
+            SustainabilitySetup."Work/Machine Center Emissions",
+            'Work/Machine Center Emissions should be enabled when Enable Value Chain Tracking is enabled');
+    end;
+
+    [ConfirmHandler]
+    procedure ConfirmHandlerYes(Question: Text[1024]; var Reply: Boolean)
+    begin
+        Reply := true;
+    end;
+}

