+namespace Microsoft.Service.Test;
+
+using Microsoft.Foundation.Reporting;
+using Microsoft.Inventory.Item;
+using Microsoft.Sales.Customer;
+using Microsoft.Service.Document;
+using System.TestLibraries.Utilities;
+
+codeunit 136154 "Service Order Print Test"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+    EventSubscriberInstance = Manual;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Service Order] [Print]
+    end;
+
+    var
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryService: Codeunit "Library - Service";
+        LibraryInventory: Codeunit "Library - Inventory";
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        IsInitialized: Boolean;
+        PrintDocumentWasCalled: Boolean;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"Service Order Print Test");
+        if IsInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"Service Order Print Test");
+
+        LibraryService.SetupServiceMgtNoSeries();
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+
+        IsInitialized := true;
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"Service Order Print Test");
+    end;
+
+    [Test]
+    [HandlerFunctions('ServiceOrderReportRequestPageHandler')]
+    procedure PrintServiceOrderWithWorkDescriptionDoesNotError()
+    var
+        Customer: Record Customer;
+        ServiceHeader: Record "Service Header";
+        ServiceItemLine: Record "Service Item Line";
+        ServiceItem: Record "Service Item";
+        ServiceLine: Record "Service Line";
+        Item: Record Item;
+        ServDocumentPrint: Codeunit "Serv. Document Print";
+        ServiceOrderPrintTest: Codeunit "Service Order Print Test";
+    begin
+        // [SCENARIO] Printing a service order with work description from the service order card page should not error
+        // [GIVEN] A service order with work description and service lines
+        Initialize();
+
+        // Create customer
+        LibrarySales.CreateCustomer(Customer);
+
+        // Create service item
+        LibraryService.CreateServiceItem(ServiceItem, Customer."No.");
+
+        // Create item for service line
+        LibraryInventory.CreateItem(Item);
+
+        // Create service header
+        LibraryService.CreateServiceHeader(ServiceHeader, ServiceHeader."Document Type"::Order, Customer."No.");
+        ServiceHeader.Description := 'New';
+        ServiceHeader.SetWorkDescription('Test');
+        ServiceHeader.Modify(true);
+
+        // Create service item line
+        LibraryService.CreateServiceItemLine(ServiceItemLine, ServiceHeader, ServiceItem."No.");
+
+        // Create service line with item
+        LibraryService.CreateServiceLine(ServiceLine, ServiceHeader, ServiceLine.Type::Item, Item."No.");
+        ServiceLine.Validate("Service Item Line No.", ServiceItemLine."Line No.");
+        ServiceLine.Validate(Quantity, 1);
+        ServiceLine.Modify(true);
+
+        // [WHEN] Print the service order - this would error before the fix with "An error occurred and the transaction is stopped"
+        // because REPORT.RunModal with IsGUI=true is not allowed in write transactions
+        // The fix adds Commit() before REPORT.RunModal when IsGUI is true
+        BindSubscription(ServiceOrderPrintTest);
+        ServiceOrderPrintTest.SetPrintDocumentWasCalled(false);
+        ServiceHeader.SetRecFilter();
+        ServDocumentPrint.PrintServiceHeader(ServiceHeader);
+        UnbindSubscription(ServiceOrderPrintTest);
+
+        // [THEN] No error occurs and the report is printed successfully
+        Assert.IsTrue(ServiceOrderPrintTest.GetPrintDocumentWasCalled(), 'Print document should have been called');
+    end;
+
+    procedure SetPrintDocumentWasCalled(Value: Boolean)
+    begin
+        PrintDocumentWasCalled := Value;
+    end;
+
+    procedure GetPrintDocumentWasCalled(): Boolean
+    begin
+        exit(PrintDocumentWasCalled);
+    end;
+
+    [EventSubscriber(ObjectType::Table, Database::"Report Selections", 'OnBeforePrintDocument', '', false, false)]
+    local procedure OnBeforePrintDocument(TempReportSelections: Record "Report Selections" temporary; IsGUI: Boolean; RecVarToPrint: Variant; var IsHandled: Boolean)
+    begin
+        // Intercept the print to verify it was called and prevent actual report execution
+        PrintDocumentWasCalled := true;
+        IsHandled := true;
+    end;
+
+    [RequestPageHandler]
+    procedure ServiceOrderReportRequestPageHandler(var ServiceOrder: TestRequestPage "Service Order")
+    begin
+        // Handle report request page if it's shown
+        ServiceOrder.Cancel().Invoke();
+    end;
+}

diff --git a/App/Layers/W1/Tests/VAT/NonDedVATJobFCY.Codeunit.al b/App/Layers/W1/Tests/VAT/NonDedVATJobFCY.Codeunit.al
new file mode 100644
index 00000000..625f5b19
--- /dev/null
+++ b/App/Layers/W1/Tests/VAT/NonDedVATJobFCY.Codeunit.al
@@ -0,0 +1,122 @@
+codeunit 134289 "Non Ded. VAT Job FCY"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Non-Deductible VAT] [Job] [Currency]
+    end;
+
+    var
+        LibraryERM: Codeunit "Library - ERM";
+        LibraryJob: Codeunit "Library - Job";
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryRandom: Codeunit "Library - Random";
+        LibraryNonDeductibleVAT: Codeunit "Library - NonDeductible VAT";
+        LibrarySetupStorage: Codeunit "Library - Setup Storage";
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        Assert: Codeunit Assert;
+        IsInitialized: Boolean;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure NonDeductibleVATAmountInJobJnlLineWhenJobHasFCYAndGenJnlLineInLCY()
+    var
+        VATPostingSetup: Record "VAT Posting Setup";
+        GenJnlLine: Record "Gen. Journal Line";
+        JobJnlLine: Record "Job Journal Line";
+        Job: Record Job;
+        JobTask: Record "Job Task";
+        Customer: Record Customer;
+        Currency: Record Currency;
+        JobTransferLine: Codeunit "Job Transfer Line";
+        NonDedVATAmountBeforeConversion: Decimal;
+        CurrencyFactor: Decimal;
+        ExpectedNonDedVATAmountLCY: Decimal;
+        ExpectedUnitCostLCY: Decimal;
+        ExpectedTotalCostLCY: Decimal;
+    begin
+        // [SCENARIO] Non-Deductible VAT Amount is correctly converted when posting a Gen. Journal Line
+        // in LCY (e.g., DKK) to a Job that has a foreign currency (e.g., EUR).
+        // Bug: Before the fix, the "Non-Deductible VAT Amount LCY" was used directly without
+        // considering that the Job's currency is different, causing incorrect Project Ledger Entry amounts.
+
+        Initialize();
+        LibraryNonDeductibleVAT.SetUseForJobCost();
+
+        // [GIVEN] VAT Posting Setup with Non-Deductible VAT
+        LibraryNonDeductibleVAT.CreateNonDeductibleNormalVATPostingSetup(VATPostingSetup);
+
+        // [GIVEN] Currency (EUR) with exchange rate
+        Currency.Get(LibraryERM.CreateCurrencyWithExchangeRate(WorkDate(), LibraryRandom.RandDecInRange(5, 10, 2), LibraryRandom.RandDecInRange(5, 10, 2)));
+
+        // [GIVEN] Job with Currency Code (EUR)
+        LibrarySales.CreateCustomer(Customer);
+        LibraryJob.CreateJob(Job, Customer."No.");
+        Job.Validate("Currency Code", Currency.Code);
+        Job.Modify(true);
+        LibraryJob.CreateJobTask(Job, JobTask);
+
+        // [GIVEN] General Journal Line in LCY with Non-Deductible VAT setup and Job reference
+        CreateJobGLJournalLineWithVATSetup(GenJnlLine, JobTask, VATPostingSetup);
+
+        // Store the non-deductible VAT amount before any conversion
+        NonDedVATAmountBeforeConversion := GenJnlLine."Non-Deductible VAT Amount";
+
+        // [WHEN] Transfer from Gen. Journal Line to Job Journal Line
+        JobTransferLine.FromGenJnlLineToJnlLine(GenJnlLine, JobJnlLine);
+
+        // [THEN] The Non-Deductible VAT Amount in Job Journal Line should be converted using Job Currency Factor
+        // When GenJnlLine.Currency Code = '' and Job.Currency Code = 'EUR':
+        // CurrencyFactor = GenJnlLine."Job Currency Factor" (since GenJnlLine."Currency Factor" = 0)
+        CurrencyFactor := GenJnlLine.GetGenJnlLineToJobCurrencyFactor();
+        ExpectedNonDedVATAmountLCY := Round(NonDedVATAmountBeforeConversion * CurrencyFactor);
+
+        // Expected costs include the base cost from GenJnlLine + properly converted Non-Ded VAT
+        ExpectedUnitCostLCY := GenJnlLine."Job Unit Cost (LCY)" + Abs(Round(ExpectedNonDedVATAmountLCY / JobJnlLine.Quantity));
+        ExpectedTotalCostLCY := GenJnlLine."Job Total Cost (LCY)" + Abs(ExpectedNonDedVATAmountLCY);
+
+        Assert.AreEqual(
+            ExpectedUnitCostLCY,
+            JobJnlLine."Unit Cost (LCY)",
+            'Unit Cost (LCY) should include Non-Deductible VAT amount converted using Job currency factor');
+        Assert.AreEqual(
+            ExpectedTotalCostLCY,
+            JobJnlLine."Total Cost (LCY)",
+            'Total Cost (LCY) should include Non-Deductible VAT amount converted using Job currency factor');
+    end;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"Non Ded. VAT Job FCY");
+        LibrarySetupStorage.Restore();
+        if IsInitialized then
+            exit;
+
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"Non Ded. VAT Job FCY");
+        LibraryNonDeductibleVAT.EnableNonDeductibleVAT();
+        LibraryERMCountryData.UpdatePurchasesPayablesSetup();
+        LibrarySetupStorage.Save(Database::"VAT Setup");
+        IsInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"Non Ded. VAT Job FCY");
+    end;
+
+    local procedure CreateJobGLJournalLineWithVATSetup(var GenJnlLine: Record "Gen. Journal Line"; JobTask: Record "Job Task"; VATPostingSetup: Record "VAT Posting Setup")
+    var
+        GLAccount: Record "G/L Account";
+    begin
+        LibraryJob.CreateJobGLJournalLine(GenJnlLine."Job Line Type"::Billable, JobTask, GenJnlLine);
+        GLAccount.Get(GenJnlLine."Account No.");
+        GLAccount.Validate("VAT Bus. Posting Group", VATPostingSetup."VAT Bus. Posting Group");
+        GLAccount.Validate("VAT Prod. Posting Group", VATPostingSetup."VAT Prod. Posting Group");
+        GLAccount.Modify(true);
+        GenJnlLine.Validate("Gen. Posting Type", GenJnlLine."Gen. Posting Type"::Purchase);
+        GenJnlLine.Validate("VAT Bus. Posting Group", VATPostingSetup."VAT Bus. Posting Group");
+        GenJnlLine.Validate("VAT Prod. Posting Group", VATPostingSetup."VAT Prod. Posting Group");
+        GenJnlLine.Modify(true);
+    end;
+}

diff --git a/App/Layers/W1/Tests/SCM/SCMTransferGetReceiptLines.Codeunit.al b/App/Layers/W1/Tests/SCM/SCMTransferGetReceiptLines.Codeunit.al
