+        TransferHeader: Record "Transfer Header";
+        TransferLine: Record "Transfer Line";
+        PurchRcptHeader: Record "Purch. Rcpt. Header";
+        PurchRcptLine: Record "Purch. Rcpt. Line";
+    begin
+        // [FEATURE] [Get Receipt Lines] [Location]
+        // [SCENARIO] GetReceiptLines function shows posted purchase receipts where Location Code is only on line (not header)
+        // This tests the fix for the first issue: receipts with location only on the line were not shown
+        Initialize();
+
+        // [GIVEN] Create locations: From, To, and In-Transit
+        CreateLocationsChain(LocationFrom, LocationTo, LocationInTransit);
+
+        // [GIVEN] Create an item
+        LibraryInventory.CreateItem(Item);
+
+        // [GIVEN] Create and post purchase order with location only on the line (not on header)
+        // This simulates the repro scenario where the purchase order header has no location, but the line has the location
+        LibraryPurchase.CreatePurchHeader(PurchaseHeader, PurchaseHeader."Document Type"::Order, LibraryPurchase.CreateVendorNo());
+        // Do NOT set location on header - leave it blank
+        LibraryPurchase.CreatePurchaseLine(
+            PurchaseLine, PurchaseHeader, PurchaseLine.Type::Item, Item."No.", LibraryRandom.RandIntInRange(5, 10));
+        // Set location only on the line
+        PurchaseLine.Validate("Location Code", LocationFrom.Code);
+        PurchaseLine.Modify(true);
+        LibraryPurchase.PostPurchaseDocument(PurchaseHeader, true, false);
+
+        // Get the posted receipt
+        PurchRcptHeader.SetRange("Buy-from Vendor No.", PurchaseHeader."Buy-from Vendor No.");
+        PurchRcptHeader.FindLast();
+        PurchRcptLine.SetRange("Document No.", PurchRcptHeader."No.");
+        PurchRcptLine.SetRange(Type, PurchRcptLine.Type::Item);
+        PurchRcptLine.FindFirst();
+
+        // [GIVEN] Create transfer order from location "From" to location "To"
+        LibraryInventory.CreateTransferHeader(TransferHeader, LocationFrom.Code, LocationTo.Code, LocationInTransit.Code);
+
+        // [WHEN] Invoke "Get Receipt Lines" function and select the posted receipt line
+        LibraryVariableStorage.Enqueue(PurchRcptHeader."No."); // Purchase Receipt to select
+        LibraryVariableStorage.Enqueue(PurchRcptLine."No."); // Item No. to filter on receipt line
+        TransferHeader.GetReceiptLines();
+
+        // [THEN] Transfer line is created - this verifies the receipt was shown even though header had no location
+        TransferLine.SetRange("Document No.", TransferHeader."No.");
+        TransferLine.SetRange("Item No.", Item."No.");
+        Assert.RecordIsNotEmpty(TransferLine);
+        TransferLine.FindFirst();
+        TransferLine.TestField(Quantity, PurchRcptLine.Quantity);
+
+        LibraryVariableStorage.AssertEmpty();
+    end;
+
+    [Test]
+    [HandlerFunctions('PostedPurchaseReceiptsModalPageHandler,PostedPurchaseReceiptLinesModalPageHandler')]
+    [Scope('OnPrem')]
+    procedure GetReceiptLinesSetsApplToItemEntry()
+    var
+        LocationFrom: Record Location;
+        LocationTo: Record Location;
+        LocationInTransit: Record Location;
+        Item: Record Item;
+        PurchaseHeader: Record "Purchase Header";
+        PurchaseLine: Record "Purchase Line";
+        TransferHeader: Record "Transfer Header";
+        TransferLine: Record "Transfer Line";
+        PurchRcptHeader: Record "Purch. Rcpt. Header";
+        PurchRcptLine: Record "Purch. Rcpt. Line";
+        ItemLedgerEntry: Record "Item Ledger Entry";
+    begin
+        // [FEATURE] [Get Receipt Lines] [Appl.-to Item Entry]
+        // [SCENARIO] GetReceiptLines function sets "Appl.-to Item Entry" on Transfer Line
+        // This tests the fix for the second issue: Appl.-to Item Entry was not set when selecting a specific receipt line
+        Initialize();
+
+        // [GIVEN] Create locations: From, To, and In-Transit
+        CreateLocationsChain(LocationFrom, LocationTo, LocationInTransit);
+
+        // [GIVEN] Create an item with FIFO costing method
+        LibraryInventory.CreateItem(Item);
+        Item.Validate("Costing Method", Item."Costing Method"::FIFO);
+        Item.Modify(true);
+
+        // [GIVEN] Create and post purchase order with location on header
+        LibraryPurchase.CreatePurchaseDocumentWithItem(
+            PurchaseHeader, PurchaseLine, PurchaseHeader."Document Type"::Order, '',
+            Item."No.", LibraryRandom.RandIntInRange(5, 10), LocationFrom.Code, WorkDate());
+        LibraryPurchase.PostPurchaseDocument(PurchaseHeader, true, false);
+
+        // Get the posted receipt
+        PurchRcptHeader.SetRange("Buy-from Vendor No.", PurchaseHeader."Buy-from Vendor No.");
+        PurchRcptHeader.FindLast();
+        PurchRcptLine.SetRange("Document No.", PurchRcptHeader."No.");
+        PurchRcptLine.SetRange(Type, PurchRcptLine.Type::Item);
+        PurchRcptLine.FindFirst();
+
+        // Get the Item Ledger Entry for this receipt line
+        ItemLedgerEntry.SetCurrentKey("Document No.");
+        ItemLedgerEntry.SetRange("Document No.", PurchRcptHeader."No.");
+        ItemLedgerEntry.SetRange("Document Type", ItemLedgerEntry."Document Type"::"Purchase Receipt");
+        ItemLedgerEntry.SetRange("Document Line No.", PurchRcptLine."Line No.");
+        ItemLedgerEntry.FindFirst();
+
+        // [GIVEN] Create transfer order from location "From" to location "To"
+        LibraryInventory.CreateTransferHeader(TransferHeader, LocationFrom.Code, LocationTo.Code, LocationInTransit.Code);
+
+        // [WHEN] Invoke "Get Receipt Lines" function and select the posted receipt line
+        LibraryVariableStorage.Enqueue(PurchRcptHeader."No."); // Purchase Receipt to select
+        LibraryVariableStorage.Enqueue(PurchRcptLine."No."); // Item No. to filter on receipt line
+        TransferHeader.GetReceiptLines();
+
+        // [THEN] Transfer line is created with "Appl.-to Item Entry" set to the ILE from the selected receipt
+        TransferLine.SetRange("Document No.", TransferHeader."No.");
+        TransferLine.SetRange("Item No.", Item."No.");
+        Assert.RecordIsNotEmpty(TransferLine);
+        TransferLine.FindFirst();
+        
+        // [THEN] "Appl.-to Item Entry" should be set to the Item Ledger Entry from the purchase receipt
+        Assert.AreEqual(
+            ItemLedgerEntry."Entry No.",
+            TransferLine."Appl.-to Item Entry",
+            'Appl.-to Item Entry should be set to the ILE from the selected purchase receipt line');
+
+        LibraryVariableStorage.AssertEmpty();
+    end;
+
+    local procedure Initialize()
+    begin
+        LibraryTestInitialize.OnTestInitialize(CODEUNIT::"SCM Transfer Get Receipt Lines");
+        LibraryVariableStorage.Clear();
+        LibrarySetupStorage.Restore();
+
+        if isInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(CODEUNIT::"SCM Transfer Get Receipt Lines");
+
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        LibraryERMCountryData.UpdatePurchasesPayablesSetup();
+
+        isInitialized := true;
+
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(CODEUNIT::"SCM Transfer Get Receipt Lines");
+    end;
+
+    local procedure CreateLocationsChain(var FromLocation: Record Location; var ToLocation: Record Location; var TransitLocation: Record Location)
+    var
+        TransferRoute: Record "Transfer Route";
+    begin
+        LibraryWarehouse.CreateLocationWithInventoryPostingSetup(FromLocation);
+        LibraryWarehouse.CreateLocationWithInventoryPostingSetup(ToLocation);
+        LibraryWarehouse.CreateInTransitLocation(TransitLocation);
+        LibraryInventory.CreateTransferRoute(TransferRoute, FromLocation.Code, ToLocation.Code);
+        TransferRoute.Validate("In-Transit Code", TransitLocation.Code);
+        TransferRoute.Modify(true);
+    end;
+
+    [ModalPageHandler]
+    [Scope('OnPrem')]
+    procedure PostedPurchaseReceiptsModalPageHandler(var PostedPurchaseReceipts: TestPage "Posted Purchase Receipts")
+    var
+        PurchRcptHeader: Record "Purch. Rcpt. Header";
+    begin
+        PurchRcptHeader.Get(LibraryVariableStorage.DequeueText());
+        PostedPurchaseReceipts.GoToRecord(PurchRcptHeader);
+        PostedPurchaseReceipts.OK().Invoke();
+    end;
+
+    [ModalPageHandler]
+    [Scope('OnPrem')]
+    procedure PostedPurchaseReceiptLinesModalPageHandler(var PostedPurchaseReceiptLines: TestPage "Posted Purchase Receipt Lines")
+    var
+        PurchRcptLine: Record "Purch. Rcpt. Line";
+    begin
+        PurchRcptLine.SetRange("No.", LibraryVariableStorage.DequeueText());
+        PurchRcptLine.FindFirst();
+        PostedPurchaseReceiptLines.GoToRecord(PurchRcptLine);
+        PostedPurchaseReceiptLines.OK().Invoke();
+    end;
+}

