+        LibraryTestInitialize.OnTestInitialize(CODEUNIT::"SCM Assembly Lines Show Doc");
+        if Initialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(CODEUNIT::"SCM Assembly Lines Show Doc");
+
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        SetupAssemblyNoSeries();
+        Initialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(CODEUNIT::"SCM Assembly Lines Show Doc");
+    end;
+
+    local procedure SetupAssemblyNoSeries()
+    var
+        AssemblySetup: Record "Assembly Setup";
+    begin
+        AssemblySetup.Get();
+        if AssemblySetup."Assembly Order Nos." = '' then
+            AssemblySetup.Validate("Assembly Order Nos.", LibraryUtility.GetGlobalNoSeriesCode());
+        if AssemblySetup."Assembly Quote Nos." = '' then
+            AssemblySetup.Validate("Assembly Quote Nos.", LibraryUtility.GetGlobalNoSeriesCode());
+        if AssemblySetup."Blanket Assembly Order Nos." = '' then
+            AssemblySetup.Validate("Blanket Assembly Order Nos.", LibraryUtility.GetGlobalNoSeriesCode());
+        AssemblySetup.Modify(true);
+    end;
+
+    local procedure CreateAssemblyItem(): Code[20]
+    var
+        Item: Record Item;
+        ChildItem: Record Item;
+        BOMComponent: Record "BOM Component";
+    begin
+        LibraryInventory.CreateItem(Item);
+        LibraryInventory.CreateItem(ChildItem);
+        LibraryAssembly.CreateAssemblyListComponent(BOMComponent.Type::Item, ChildItem."No.", Item."No.", '', 0, 1, true);
+        exit(Item."No.");
+    end;
+
+    [Test]
+    [HandlerFunctions('BlanketAssemblyOrderPageHandler')]
+    [Scope('OnPrem')]
+    procedure ShowDocumentOpensBlanketAssemblyOrderForBlanketOrderLine()
+    var
+        AssemblyHeader: Record "Assembly Header";
+        AssemblyLine: Record "Assembly Line";
+        AssemblyLines: TestPage "Assembly Lines";
+    begin
+        // [FEATURE] [UI] [Blanket Assembly Order]
+        // [SCENARIO] Show Document action on Assembly Lines page opens Blanket Assembly Order page when line belongs to a Blanket Assembly Order
+        Initialize();
+
+        // [GIVEN] Create a Blanket Assembly Order with an item
+        CreateBlanketAssemblyOrder(AssemblyHeader, CreateAssemblyItem());
+        FindAssemblyLine(AssemblyHeader, AssemblyLine);
+
+        // [WHEN] Open Assembly Lines page, filter to the blanket order line and invoke Show Document action
+        AssemblyLines.OpenView();
+        AssemblyLines.Filter.SetFilter("Document Type", Format(AssemblyLine."Document Type"));
+        AssemblyLines.Filter.SetFilter("Document No.", AssemblyLine."Document No.");
+        AssemblyLines.First();
+        AssemblyLines."Show Document".Invoke();
+
+        // [THEN] The Blanket Assembly Order page is opened (verified in BlanketAssemblyOrderPageHandler)
+        AssemblyLines.Close();
+    end;
+
+    [Test]
+    [HandlerFunctions('AssemblyOrderPageHandler')]
+    [Scope('OnPrem')]
+    procedure ShowDocumentOpensAssemblyOrderForOrderLine()
+    var
+        AssemblyHeader: Record "Assembly Header";
+        AssemblyLine: Record "Assembly Line";
+        AssemblyLines: TestPage "Assembly Lines";
+    begin
+        // [FEATURE] [UI] [Assembly Order]
+        // [SCENARIO] Show Document action on Assembly Lines page opens Assembly Order page when line belongs to an Assembly Order
+        Initialize();
