+        LibraryAssembly.CreateAssemblyHeader(AssemblyHeader, WorkDate2, CreateAssemblyItem(), '', 1, '');
+        FindAssemblyLine(AssemblyHeader, AssemblyLine);
+
+        // [WHEN] Open Assembly Lines page, filter to the order line and invoke Show Document action
+        AssemblyLines.OpenView();
+        AssemblyLines.Filter.SetFilter("Document Type", Format(AssemblyLine."Document Type"));
+        AssemblyLines.Filter.SetFilter("Document No.", AssemblyLine."Document No.");
+        AssemblyLines.First();
+        AssemblyLines."Show Document".Invoke();
+
+        // [THEN] The Assembly Order page is opened (verified in AssemblyOrderPageHandler)
+        AssemblyLines.Close();
+    end;
+
+    [Test]
+    [HandlerFunctions('AssemblyQuotePageHandler')]
+    [Scope('OnPrem')]
+    procedure ShowDocumentOpensAssemblyQuoteForQuoteLine()
+    var
+        AssemblyHeader: Record "Assembly Header";
+        AssemblyLine: Record "Assembly Line";
+        AssemblyLines: TestPage "Assembly Lines";
+    begin
+        // [FEATURE] [UI] [Assembly Quote]
+        // [SCENARIO] Show Document action on Assembly Lines page opens Assembly Quote page when line belongs to an Assembly Quote
+        Initialize();
+
+        // [GIVEN] Create an Assembly Quote with an item
+        LibraryAssembly.CreateAssemblyQuote(AssemblyHeader, WorkDate2, CreateAssemblyItem(), '', 1, '');
+        FindAssemblyLine(AssemblyHeader, AssemblyLine);
+
+        // [WHEN] Open Assembly Lines page, filter to the quote line and invoke Show Document action
+        AssemblyLines.OpenView();
+        AssemblyLines.Filter.SetFilter("Document Type", Format(AssemblyLine."Document Type"));
+        AssemblyLines.Filter.SetFilter("Document No.", AssemblyLine."Document No.");
+        AssemblyLines.First();
+        AssemblyLines."Show Document".Invoke();
+
+        // [THEN] The Assembly Quote page is opened (verified in AssemblyQuotePageHandler)
+        AssemblyLines.Close();
