+codeunit 134290 "Non-Ded. VAT Clear On Zero Cost"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Non-Deductible VAT]
+    end;
+
+    var
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibraryNonDeductibleVAT: Codeunit "Library - NonDeductible VAT";
+        LibrarySetupStorage: Codeunit "Library - Setup Storage";
+        LibraryPurchase: Codeunit "Library - Purchase";
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryRandom: Codeunit "Library - Random";
+        Assert: Codeunit Assert;
+        isInitialized: Boolean;
+
+    [Test]
+    procedure NonDeductibleVATClearedWhenDirectUnitCostSetToZero()
+    var
+        VATPostingSetup: Record "VAT Posting Setup";
+        PurchHeader: Record "Purchase Header";
+        PurchLine: Record "Purchase Line";
+    begin
+        // [SCENARIO] When changing the Direct Unit Cost to 0 in the purchase invoice line, the Non-Deductible VAT is removed
+        // [GIVEN] Non-Deductible VAT is enabled
+        // [GIVEN] VAT Posting Setup with Non-Deductible VAT enabled (e.g., 10%)
+        // [GIVEN] A purchase invoice with a line that has Direct Unit Cost > 0 and Non-Deductible VAT Amount > 0
+        // [WHEN] The Direct Unit Cost is changed to 0
+        // [THEN] The Non-Deductible VAT Base and Non-Deductible VAT Amount should be 0
+
+        Initialize();
+
+        // [GIVEN] VAT Posting Setup with Non-Deductible VAT
+        LibraryNonDeductibleVAT.CreateNonDeductibleNormalVATPostingSetup(VATPostingSetup);
+
+        // [GIVEN] Purchase invoice with item connected to Non-Deductible VAT Posting Setup
+        LibraryPurchase.CreatePurchHeader(
+            PurchHeader, PurchHeader."Document Type"::Invoice,
+            LibraryPurchase.CreateVendorWithVATBusPostingGroup(VATPostingSetup."VAT Bus. Posting Group"));
+        LibraryPurchase.CreatePurchaseLine(
+            PurchLine, PurchHeader, PurchLine.Type::Item,
+            LibraryInventory.CreateItemWithVATProdPostingGroup(VATPostingSetup."VAT Prod. Posting Group"), LibraryRandom.RandInt(10));
+
+        // [GIVEN] Set Direct Unit Cost to a positive value, which should populate Non-Deductible VAT fields
+        PurchLine.Validate("Direct Unit Cost", LibraryRandom.RandDec(100, 2));
+        PurchLine.Modify(true);
+
+        // Verify Non-Deductible VAT fields are populated before the test
+        Assert.AreNotEqual(0, PurchLine."Non-Deductible VAT Base", 'Non-Deductible VAT Base should not be 0 before changing Direct Unit Cost to 0');
+        Assert.AreNotEqual(0, PurchLine."Non-Deductible VAT Amount", 'Non-Deductible VAT Amount should not be 0 before changing Direct Unit Cost to 0');
+
+        // [WHEN] Change Direct Unit Cost to 0
+        PurchLine.Validate("Direct Unit Cost", 0);
+        PurchLine.Modify(true);
+
+        // [THEN] Non-Deductible VAT Base and Non-Deductible VAT Amount should be 0
+        Assert.AreEqual(0, PurchLine."Non-Deductible VAT Base", 'Non-Deductible VAT Base should be 0 when Direct Unit Cost is 0');
+        Assert.AreEqual(0, PurchLine."Non-Deductible VAT Amount", 'Non-Deductible VAT Amount should be 0 when Direct Unit Cost is 0');
+        Assert.AreEqual(0, PurchLine.Amount, 'Amount should be 0 when Direct Unit Cost is 0');
+        Assert.AreEqual(0, PurchLine."VAT Base Amount", 'VAT Base Amount should be 0 when Direct Unit Cost is 0');
+        Assert.AreEqual(0, PurchLine."Amount Including VAT", 'Amount Including VAT should be 0 when Direct Unit Cost is 0');
+    end;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"Non-Ded. VAT Clear On Zero Cost");
+        LibrarySetupStorage.Restore();
+        if isInitialized then
+            exit;
+
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"Non-Ded. VAT Clear On Zero Cost");
+        LibraryNonDeductibleVAT.EnableNonDeductibleVAT();
+        LibraryERMCountryData.UpdatePurchasesPayablesSetup();
+        LibrarySetupStorage.Save(Database::"VAT Setup");
+        isInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"Non-Ded. VAT Clear On Zero Cost");
+    end;
+}

