@@ -0,0 +1,121 @@
+// ------------------------------------------------------------------------------------------------
+// Copyright (c) Microsoft Corporation. All rights reserved.
+// Licensed under the MIT License. See License.txt in the project root for license information.
+// ------------------------------------------------------------------------------------------------
+namespace Microsoft.Manufacturing.Test;
+
+using Microsoft.Inventory.Item;
+using Microsoft.Manufacturing.Document;
+using Microsoft.Manufacturing.ProductionBOM;
+
+codeunit 137085 "SCM Prod Ord Comp Qty Rounding"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Manufacturing] [Production Order] [SCM] [Rounding]
+        IsInitialized := false;
+    end;
+
+    var
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryManufacturing: Codeunit "Library - Manufacturing";
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        Assert: Codeunit Assert;
+        IsInitialized: Boolean;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure ProdOrderCompQtyPerNotZeroWhenComponentUOMQtyRoundingPrecisionIsOne()
+    var
+        CompItem: Record Item;
+        ProdItem: Record Item;
+        ItemUnitOfMeasure: Record "Item Unit of Measure";
+        ProductionBOMHeader: Record "Production BOM Header";
+        ProductionBOMLine: Record "Production BOM Line";
+        ProductionOrder: Record "Production Order";
+        ProdOrderComponent: Record "Prod. Order Component";
+        QuantityPer: Decimal;
+    begin
+        // [SCENARIO] When a component's Item UOM has 'Qty. Rounding Precision' = 1, and a Finished Good 
+        // consumes partial quantity, the Prod. Order Component should have correct 'Quantity per' and 
+        // 'Expected Quantity' values, not 0.
+        Initialize();
+
+        // [GIVEN] Component item with Base UOM "Qty. Rounding Precision" = 1
+        // [GIVEN] Component Item has Replenishment System = Purchase, Rounding Precision = 0.01
+        QuantityPer := 0.09;
+        CreateItemWithRoundingPrecision(CompItem, CompItem."Replenishment System"::Purchase, 0.01);
+        ItemUnitOfMeasure.Get(CompItem."No.", CompItem."Base Unit of Measure");
+        ItemUnitOfMeasure.Validate("Qty. Rounding Precision", 1);
+        ItemUnitOfMeasure.Modify(true);
+
+        // [GIVEN] Finished Good Item with Replenishment System = Prod. Order, Rounding Precision = 1
+        CreateItemWithRoundingPrecision(ProdItem, ProdItem."Replenishment System"::"Prod. Order", 1);
+
+        // [GIVEN] Production BOM for FG Item consuming Component with "Quantity per" = 0.09
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader, ProdItem."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(
+            ProductionBOMHeader, ProductionBOMLine, '', ProductionBOMLine.Type::Item, CompItem."No.", QuantityPer);
+        LibraryManufacturing.UpdateProductionBOMStatus(ProductionBOMHeader, ProductionBOMHeader.Status::Certified);
+        UpdateProductionBOMOnItem(ProdItem, ProductionBOMHeader."No.");
+
+        // [WHEN] Create and refresh Released Production Order for 1 quantity of FG Item
+        LibraryManufacturing.CreateAndRefreshProductionOrder(
+            ProductionOrder, ProductionOrder.Status::Released, ProductionOrder."Source Type"::Item, ProdItem."No.", 1);
+
+        // [THEN] Prod. Order Component "Quantity per" = 0.09 (not 0)
+        // [THEN] Prod. Order Component "Expected Quantity" = 0.09 (not 0)
+        FindProdOrderComponent(ProdOrderComponent, ProductionOrder.Status, ProductionOrder."No.", CompItem."No.");
+        Assert.AreEqual(
+            QuantityPer,
+            ProdOrderComponent."Quantity per",
+            'Quantity per should equal the BOM line Quantity per, not be rounded to 0');
+        Assert.AreEqual(
+            QuantityPer,
+            ProdOrderComponent."Expected Quantity",
+            'Expected Quantity should equal the BOM line Quantity per, not be rounded to 0');
+    end;
+
+    local procedure Initialize()
+    var
