+    [Test]
+    procedure AvailWarningConsidersDueDateNotAllDemand()
+    var
+        AsmItem: Record Item;
+        CompItem: Record Item;
+        BOMComponent: Record "BOM Component";
+        ItemJournalLine: Record "Item Journal Line";
+        AssemblyHeader: array[2] of Record "Assembly Header";
+        AssemblyLine: array[2] of Record "Assembly Line";
+        QtyPerBom: Decimal;
+        OrderDueDate1: Date;
+        OrderDueDate2: Date;
+    begin
+        // [FEATURE] [Assembly] [Availability] [Due Date]
+        // [SCENARIO 123456] Availability warning on Assembly Order Line should consider Due Dates, not all future demand.
+        // The assembly order with earlier Due Date should show no warning if there's sufficient inventory by that date,
+        // even if later assembly orders create additional component demand.
+        Initialize();
+
+        // [GIVEN] Assembly item with component. Qty Per = 2 means 1 assembly requires 2 components.
+        QtyPerBom := 2;
+        LibraryInventory.CreateItem(AsmItem);
