+          BOMComponent, AsmItem."No.", BOMComponent.Type::Item, CompItem."No.", QtyPerBom, CompItem."Base Unit of Measure");
+
+        // [GIVEN] Post 2 pcs of the component to inventory.
+        LibraryInventory.CreateItemJournalLineInItemTemplate(ItemJournalLine, CompItem."No.", '', '', 2);
+        LibraryInventory.PostItemJournalLine(ItemJournalLine."Journal Template Name", ItemJournalLine."Journal Batch Name");
+
+        // [GIVEN] First assembly order for 1 pc on WorkDate() + 5 (requires 2 components).
+        OrderDueDate1 := WorkDate() + 5;
+        LibraryAssembly.CreateAssemblyHeader(AssemblyHeader[1], OrderDueDate1, AsmItem."No.", '', 1, '');
+        FindAssemblyLine(AssemblyLine[1], AssemblyHeader[1], CompItem."No.");
+
+        // [GIVEN] Second assembly order for 3 pcs on WorkDate() + 10 (requires 6 components).
+        // Total demand = 8, but only 2 in inventory.
+        OrderDueDate2 := WorkDate() + 10;
+        LibraryAssembly.CreateAssemblyHeader(AssemblyHeader[2], OrderDueDate2, AsmItem."No.", '', 3, '');
+        FindAssemblyLine(AssemblyLine[2], AssemblyHeader[2], CompItem."No.");
+
+        // [WHEN] Check availability warning on the first assembly order line.
+        AssemblyLine[1].Find();
+        AssemblyLine[1].UpdateAvailWarning();
+
+        // [THEN] First assembly order should NOT have availability warning.
+        // We have 2 in inventory, require 2 for the first order by due date 1.
+        // The demand from the second order (due date 2) should not impact the first order's warning.
+        Assert.IsFalse(
+            AssemblyLine[1]."Avail. Warning",
+            'First assembly order line should not have availability warning because inventory is sufficient for its due date.');
+
+        // [WHEN] Check availability warning on the second assembly order line.
+        AssemblyLine[2].Find();
+        AssemblyLine[2].UpdateAvailWarning();
+
+        // [THEN] Second assembly order should have availability warning.
+        // After the first order consumes 2, we need 6 more but there's none left.
+        Assert.IsTrue(
