+        Assert.IsTrue(Result > 0, 'Custom Amount should always be positive');
+    end;
+
+    local procedure CreateGLEntry(var GLEntry: Record "G/L Entry"; GLAccountNo: Code[20]; Amount: Decimal; PostingDate: Date)
+    var
+        NextEntryNo: Integer;
+    begin
+        GLEntry.Reset();
+        if GLEntry.FindLast() then
+            NextEntryNo := GLEntry."Entry No." + 1
+        else
+            NextEntryNo := 1;
+
+        GLEntry.Init();
+        GLEntry."Entry No." := NextEntryNo;
+        GLEntry."G/L Account No." := GLAccountNo;
+        GLEntry.Amount := Amount;
+        GLEntry."Posting Date" := PostingDate;
+        GLEntry."Document No." := 'TEST001';
