+++ b/App/Layers/W1/Tests/Job/RecurringJobJournalTest.Codeunit.al
@@ -0,0 +1,191 @@
+codeunit 136399 "Recurring Job Journal Test"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Recurring Job Journal]
+        IsInitialized := false;
+    end;
+
+    var
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibraryJob: Codeunit "Library - Job";
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryResource: Codeunit "Library - Resource";
+        LibraryRandom: Codeunit "Library - Random";
+        LibraryUtility: Codeunit "Library - Utility";
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+        IsInitialized: Boolean;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure RecurringJobJnlVariableMethodPreservesUnitCostAndPrice()
+    var
+        JobJournalTemplate: Record "Job Journal Template";
+        JobJournalBatch: Record "Job Journal Batch";
+        JobJournalLine: Record "Job Journal Line";
+        JobTask: Record "Job Task";
+        Resource: Record Resource;
+        OriginalUnitCost: Decimal;
+        OriginalUnitPrice: Decimal;
+    begin
+        // [FEATURE] [Recurring Job Journal] [Variable Method]
+        // [SCENARIO] After posting a recurring job journal line with Variable method, Unit Cost and Unit Price are preserved
+        // This allows users to simply update Quantity for next posting without re-validating the Resource/Item
+
+        // [GIVEN] A Recurring Job Journal Template and Batch
+        Initialize();
+        CreateRecurringJobJournalBatch(JobJournalTemplate, JobJournalBatch);
+
+        // [GIVEN] A Job with Job Task and a Resource with Unit Cost and Unit Price
+        CreateJobWithJobTask(JobTask);
+        LibraryResource.CreateResourceNew(Resource);
+        Resource.Validate("Unit Cost", LibraryRandom.RandDecInRange(10, 100, 2));
+        Resource.Validate("Unit Price", LibraryRandom.RandDecInRange(100, 200, 2));
+        Resource.Modify(true);
+
+        // [GIVEN] A Job Journal Line with Recurring Method = Variable, Unit Cost and Unit Price
+        CreateRecurringJobJournalLine(
+            JobJournalLine, JobJournalTemplate.Name, JobJournalBatch.Name,
+            JobTask, JobJournalLine.Type::Resource, Resource."No.");
+
+        OriginalUnitCost := JobJournalLine."Unit Cost";
+        OriginalUnitPrice := JobJournalLine."Unit Price";
+
+        // [WHEN] Post the Job Journal
+        Codeunit.Run(Codeunit::"Job Jnl.-Post Batch", JobJournalLine);
+
+        // [THEN] The Job Journal Line still exists (recurring) with Quantity = 0 but Unit Cost and Unit Price preserved
+        JobJournalLine.SetRange("Journal Template Name", JobJournalTemplate.Name);
+        JobJournalLine.SetRange("Journal Batch Name", JobJournalBatch.Name);
+        JobJournalLine.FindFirst();
+
+        Assert.AreEqual(0, JobJournalLine.Quantity, 'Quantity should be reset to 0 for Variable recurring method');
+        Assert.AreEqual(OriginalUnitCost, JobJournalLine."Unit Cost", 'Unit Cost should be preserved after posting');
+        Assert.AreEqual(OriginalUnitPrice, JobJournalLine."Unit Price", 'Unit Price should be preserved after posting');
+    end;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure RecurringJobJnlFixedMethodDeletesAmounts()
+    var
+        JobJournalTemplate: Record "Job Journal Template";
+        JobJournalBatch: Record "Job Journal Batch";
+        JobJournalLine: Record "Job Journal Line";
+        JobTask: Record "Job Task";
+        Resource: Record Resource;
+        OriginalQuantity: Decimal;
+        OriginalUnitCost: Decimal;
+        OriginalUnitPrice: Decimal;
+    begin
+        // [FEATURE] [Recurring Job Journal] [Fixed Method]
+        // [SCENARIO] After posting a recurring job journal line with Fixed method, all values including Quantity are preserved
+
+        // [GIVEN] A Recurring Job Journal Template and Batch
+        Initialize();
+        CreateRecurringJobJournalBatch(JobJournalTemplate, JobJournalBatch);
+
+        // [GIVEN] A Job with Job Task and a Resource
+        CreateJobWithJobTask(JobTask);
+        LibraryResource.CreateResourceNew(Resource);
+        Resource.Validate("Unit Cost", LibraryRandom.RandDecInRange(10, 100, 2));
+        Resource.Validate("Unit Price", LibraryRandom.RandDecInRange(100, 200, 2));
+        Resource.Modify(true);
+
+        // [GIVEN] A Job Journal Line with Recurring Method = Fixed
+        CreateRecurringJobJournalLineWithMethod(
+            JobJournalLine, JobJournalTemplate.Name, JobJournalBatch.Name,
+            JobTask, JobJournalLine.Type::Resource, Resource."No.",
+            JobJournalLine."Recurring Method"::Fixed);
+
+        OriginalQuantity := JobJournalLine.Quantity;
+        OriginalUnitCost := JobJournalLine."Unit Cost";
+        OriginalUnitPrice := JobJournalLine."Unit Price";
+
+        // [WHEN] Post the Job Journal
+        Codeunit.Run(Codeunit::"Job Jnl.-Post Batch", JobJournalLine);
+
+        // [THEN] The Job Journal Line still exists with all values preserved (Fixed method)
+        JobJournalLine.SetRange("Journal Template Name", JobJournalTemplate.Name);
+        JobJournalLine.SetRange("Journal Batch Name", JobJournalBatch.Name);
+        JobJournalLine.FindFirst();
+
+        Assert.AreEqual(OriginalQuantity, JobJournalLine.Quantity, 'Quantity should be preserved for Fixed recurring method');
+        Assert.AreEqual(OriginalUnitCost, JobJournalLine."Unit Cost", 'Unit Cost should be preserved for Fixed recurring method');
+        Assert.AreEqual(OriginalUnitPrice, JobJournalLine."Unit Price", 'Unit Price should be preserved for Fixed recurring method');
+    end;
+
+    local procedure Initialize()
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"Recurring Job Journal Test");
+        if IsInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"Recurring Job Journal Test");
+
+        LibraryERMCountryData.UpdateGeneralLedgerSetup();
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        LibraryERMCountryData.UpdateSalesReceivablesSetup();
+        LibrarySales.SetCreditWarningsToNoWarnings();
+
+        IsInitialized := true;
+        Commit();
+
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"Recurring Job Journal Test");
+    end;
+
+    local procedure CreateRecurringJobJournalBatch(var JobJournalTemplate: Record "Job Journal Template"; var JobJournalBatch: Record "Job Journal Batch")
+    begin
+        JobJournalTemplate.Init();
+        JobJournalTemplate.Validate(Name, LibraryUtility.GenerateRandomCode(JobJournalTemplate.FieldNo(Name), Database::"Job Journal Template"));
+        JobJournalTemplate.Validate(Recurring, true);
+        JobJournalTemplate.Insert(true);
+
+        JobJournalBatch.Init();
+        JobJournalBatch.Validate("Journal Template Name", JobJournalTemplate.Name);
+        JobJournalBatch.Validate(Name, LibraryUtility.GenerateRandomCode(JobJournalBatch.FieldNo(Name), Database::"Job Journal Batch"));
+        JobJournalBatch.Insert(true);
+    end;
+
+    local procedure CreateJobWithJobTask(var JobTask: Record "Job Task")
+    var
+        Customer: Record Customer;
+        Job: Record Job;
+    begin
+        LibrarySales.CreateCustomer(Customer);
+        LibraryJob.CreateJob(Job, Customer."No.");
+        LibraryJob.CreateJobTask(Job, JobTask);
+    end;
+
+    local procedure CreateRecurringJobJournalLine(var JobJournalLine: Record "Job Journal Line"; TemplateName: Code[10]; BatchName: Code[10]; JobTask: Record "Job Task"; LineType: Enum "Job Journal Line Type"; No: Code[20])
+    begin
+        CreateRecurringJobJournalLineWithMethod(JobJournalLine, TemplateName, BatchName, JobTask, LineType, No, JobJournalLine."Recurring Method"::Variable);
+    end;
+
+    local procedure CreateRecurringJobJournalLineWithMethod(var JobJournalLine: Record "Job Journal Line"; TemplateName: Code[10]; BatchName: Code[10]; JobTask: Record "Job Task"; LineType: Enum "Job Journal Line Type"; No: Code[20]; RecurringMethod: Option)
+    var
+        RecRef: RecordRef;
+    begin
+        JobJournalLine.Init();
+        JobJournalLine.Validate("Journal Template Name", TemplateName);
+        JobJournalLine.Validate("Journal Batch Name", BatchName);
+        RecRef.GetTable(JobJournalLine);
+        JobJournalLine.Validate("Line No.", LibraryUtility.GetNewLineNo(RecRef, JobJournalLine.FieldNo("Line No.")));
+        JobJournalLine.Insert(true);
+
+        JobJournalLine.Validate("Posting Date", WorkDate());
+        JobJournalLine.Validate("Document No.", LibraryUtility.GenerateGUID());
+        JobJournalLine.Validate("Job No.", JobTask."Job No.");
+        JobJournalLine.Validate("Job Task No.", JobTask."Job Task No.");
+        JobJournalLine.Validate(Type, LineType);
+        JobJournalLine.Validate("No.", No);
+        JobJournalLine.Validate(Quantity, LibraryRandom.RandIntInRange(1, 10));
+        JobJournalLine.Validate("Recurring Method", RecurringMethod);
+        Evaluate(JobJournalLine."Recurring Frequency", '<1M>');
+        JobJournalLine.Modify(true);
+    end;
+
+}

