+codeunit 134422 "Issued Reminder Email Test"
+{
+    // Tests to verify that issued reminder emails are correctly logged in customer sent email history
+    Permissions = TableData "Issued Reminder Header" = rimd,
+                  TableData "Issued Reminder Line" = rimd;
+    EventSubscriberInstance = Manual;
+    Subtype = Test;
+    TestPermissions = NonRestrictive;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Report Selection] [Email] [Reminder]
+    end;
+
+    var
+        Assert: Codeunit Assert;
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryUtility: Codeunit "Library - Utility";
+        CapturedSourceTableIDs: List of [Integer];
+        CapturedSourceIDs: List of [Guid];
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure IssuedReminderEmailIncludesCustomerInSourceRelations()
+    var
+        Customer: Record Customer;
+        IssuedReminderHeader: Record "Issued Reminder Header";
+        ReportSelections: Record "Report Selections";
+        IssuedReminderEmailTest: Codeunit "Issued Reminder Email Test";
+        RetrievedSourceTableIDs: List of [Integer];
+        RetrievedSourceIDs: List of [Guid];
+        CustomerFound: Boolean;
+        i: Integer;
+    begin
+        // [SCENARIO] When sending email for an Issued Reminder, the customer should be added to source relations
+        // so the email appears in customer's sent email history
+
+        // [GIVEN] A customer with email
+        LibrarySales.CreateCustomer(Customer);
+        Customer."E-Mail" := 'test@contoso.com';
+        Customer.Modify();
+
+        // [GIVEN] An Issued Reminder for that customer
+        CreateIssuedReminderForCustomer(IssuedReminderHeader, Customer);
+
+        // [WHEN] Email sending is triggered for the Issued Reminder
+        BindSubscription(IssuedReminderEmailTest);
+        IssuedReminderHeader.SetRecFilter();
+        ReportSelections.SendEmailToCust(
+            ReportSelections.Usage::Reminder.AsInteger(),
+            IssuedReminderHeader,
+            IssuedReminderHeader."No.",
+            'Reminder',
+            false,
+            Customer."No.");
+        IssuedReminderEmailTest.GetCapturedData(RetrievedSourceTableIDs, RetrievedSourceIDs);
+        UnbindSubscription(IssuedReminderEmailTest);
+
+        // [THEN] The customer should be included in the source tables for the email
+        CustomerFound := false;
+        for i := 1 to RetrievedSourceTableIDs.Count do
+            if RetrievedSourceTableIDs.Get(i) = Database::Customer then
+                if RetrievedSourceIDs.Get(i) = Customer.SystemId then begin
+                    CustomerFound := true;
+                    break;
+                end;
+
+        Assert.IsTrue(CustomerFound, 'Customer should be included in email source relations for issued reminder');
+    end;
+
+    local procedure CreateIssuedReminderForCustomer(var IssuedReminderHeader: Record "Issued Reminder Header"; Customer: Record Customer)
+    var
+        IssuedReminderLine: Record "Issued Reminder Line";
+        CustomerPostingGroup: Record "Customer Posting Group";
+    begin
+        LibrarySales.CreateCustomerPostingGroup(CustomerPostingGroup);
+        CustomerPostingGroup."Additional Fee Account" := '';
+        CustomerPostingGroup.Modify();
