@@ -0,0 +1,155 @@
+codeunit 134934 "ERM Account Receivables KPIs"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Account Receivables KPIs]
+        IsInitialized := false;
+    end;
+
+    var
+        Assert: Codeunit Assert;
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryUtility: Codeunit "Library - Utility";
+        LibraryRandom: Codeunit "Library - Random";
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        IsInitialized: Boolean;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure TotalOverdueLCYUsesTodayNotWorkDate()
+    var
+        FinanceCue: Record "Finance Cue";
+        DetailedCustLedgEntry: Record "Detailed Cust. Ledg. Entry";
+        Customer: Record Customer;
+        AccountReceivablesKPIs: TestPage "Account Receivables KPIs";
+        OverdueAmountDueYesterday: Decimal;
+        AmountDueTomorrow: Decimal;
+        SavedWorkDate: Date;
+    begin
+        // [SCENARIO] Total Overdue (LCY) cue uses Today() for filtering, not WorkDate()
+        // [GIVEN] WorkDate is set to a date in the future (after Today)
+        Initialize();
+        SavedWorkDate := WorkDate();
+
+        // Set WorkDate to 30 days in the future
+        // If the bug exists (using WorkDate), entries due before WorkDate would be considered overdue
+        // This means entries due tomorrow (Today + 1) would be included in overdue if using WorkDate (Today + 30)
+        // With the fix (using Today), entries due tomorrow should NOT be included
+        WorkDate(Today() + 30);
+
+        // [GIVEN] Customer with detailed ledger entries
+        LibrarySales.CreateCustomer(Customer);
+
+        // [GIVEN] Entry with due date before Today (overdue regardless of which date is used)
+        OverdueAmountDueYesterday := LibraryRandom.RandDecInRange(100, 1000, 2);
+        MockDtldCustLedgEntry(DetailedCustLedgEntry, Customer."No.", Today() - 1, OverdueAmountDueYesterday);
+
+        // [GIVEN] Entry with due date after Today but before WorkDate
+        // This entry would be incorrectly included as overdue if using WorkDate (Today + 30)
+        // With the fix, this entry should NOT be included since it's due tomorrow
+        AmountDueTomorrow := LibraryRandom.RandDecInRange(100, 1000, 2);
+        MockDtldCustLedgEntry(DetailedCustLedgEntry, Customer."No.", Today() + 1, AmountDueTomorrow);
+
+        // [WHEN] Open Account Receivables KPIs page
+        AccountReceivablesKPIs.OpenView();
+
+        // [THEN] The Total Overdue (LCY) should include only entries overdue as of Today
+        // With the fix (using Today), only the entry due yesterday should be included
+        // If the bug existed (using WorkDate = Today + 30), both entries would be included
+        FinanceCue.Reset();
+        FinanceCue.SetRange("Overdue Date Filter", 0D, Today());
+        if not FinanceCue.Get() then begin
+            FinanceCue.Init();
+            FinanceCue.Insert();
+        end;
+        FinanceCue.CalcFields("Total Overdue (LCY)");
+
+        Assert.AreEqual(OverdueAmountDueYesterday, FinanceCue."Total Overdue (LCY)",
+            'Total Overdue (LCY) should use Today() for filtering, not WorkDate(). Entry due tomorrow should not be included.');
+
+        AccountReceivablesKPIs.Close();
+
+        // Cleanup
+        WorkDate(SavedWorkDate);
+    end;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure TotalOverdueLCYFilterSetOnPageOpen()
+    var
+        FinanceCue: Record "Finance Cue";
+        DetailedCustLedgEntry: Record "Detailed Cust. Ledg. Entry";
+        Customer: Record Customer;
+        AccountReceivablesKPIs: TestPage "Account Receivables KPIs";
+        OverdueAmount: Decimal;
+        NotOverdueAmount: Decimal;
+        SavedWorkDate: Date;
+    begin
+        // [SCENARIO] When Account Receivables KPIs page opens, Overdue Date Filter is set using Today() not WorkDate()
+        // [GIVEN] WorkDate is set far in the future
+        Initialize();
+        SavedWorkDate := WorkDate();
+
+        // Set WorkDate to 60 days in the future
+        WorkDate(Today() + 60);
+
+        // [GIVEN] Customer with detailed ledger entries
+        LibrarySales.CreateCustomer(Customer);
+
+        // [GIVEN] Entry with due date 5 days ago (overdue as of Today)
+        OverdueAmount := LibraryRandom.RandDecInRange(100, 1000, 2);
+        MockDtldCustLedgEntry(DetailedCustLedgEntry, Customer."No.", Today() - 5, OverdueAmount);
+
+        // [GIVEN] Entry with due date 10 days from now (would be overdue if using WorkDate = Today + 60)
+        NotOverdueAmount := LibraryRandom.RandDecInRange(100, 1000, 2);
+        MockDtldCustLedgEntry(DetailedCustLedgEntry, Customer."No.", Today() + 10, NotOverdueAmount);
+
+        // [WHEN] Open Account Receivables KPIs page
+        AccountReceivablesKPIs.OpenView();
+
+        // [THEN] The Finance Cue record should have Overdue Date Filter set based on Today
+        // Only the entry due 5 days ago should be counted, not the one due in 10 days
+        FinanceCue.Reset();
+        FinanceCue.SetRange("Overdue Date Filter", 0D, Today());
+        if FinanceCue.Get() then begin
+            FinanceCue.CalcFields("Total Overdue (LCY)");
+            Assert.AreEqual(OverdueAmount, FinanceCue."Total Overdue (LCY)",
+                'Overdue Date Filter should use Today(). Entry due in 10 days should not be counted as overdue.');
+        end;
+
+        AccountReceivablesKPIs.Close();
+
+        // Cleanup
+        WorkDate(SavedWorkDate);
+    end;
+
+    local procedure Initialize()
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"ERM Account Receivables KPIs");
+
+        if IsInitialized then
+            exit;
+
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"ERM Account Receivables KPIs");
+
+        IsInitialized := true;
+        Commit();
+
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"ERM Account Receivables KPIs");
+    end;
+
+    local procedure MockDtldCustLedgEntry(var DetailedCustLedgEntry: Record "Detailed Cust. Ledg. Entry"; CustNo: Code[20]; InitialEntryDueDate: Date; AmountLCY: Decimal)
+    begin
+        DetailedCustLedgEntry.Init();
+        DetailedCustLedgEntry."Entry No." := LibraryUtility.GetNewRecNo(DetailedCustLedgEntry, DetailedCustLedgEntry.FieldNo("Entry No."));
+        DetailedCustLedgEntry."Customer No." := CustNo;
+        DetailedCustLedgEntry."Posting Date" := Today();
+        DetailedCustLedgEntry."Initial Entry Due Date" := InitialEntryDueDate;
+        DetailedCustLedgEntry.Amount := AmountLCY;
+        DetailedCustLedgEntry."Amount (LCY)" := AmountLCY;
+        DetailedCustLedgEntry.Insert();
+    end;
+}

