+        RequisitionLine: Record "Requisition Line";
+        ReqJnlManagement: Codeunit ReqJnlManagement;
+        CurrentJnlBatchName: Code[10];
+    begin
+        // [FEATURE] [Requisition Worksheet] [Planning]
+        // [SCENARIO] When opening Planning Worksheet from Item Availability by Event, the correct batch is opened
+        // based on the requisition line's template and batch, not the last used batch.
+
+        // [GIVEN] Two requisition worksheet templates, each with a batch
+        CreateReqWorksheetTemplate(ReqWkshTemplate[1]);
+        LibraryPlanning.CreateRequisitionWkshName(RequisitionWkshName[1], ReqWkshTemplate[1].Name);
+        CreateReqWorksheetTemplate(ReqWkshTemplate[2]);
+        LibraryPlanning.CreateRequisitionWkshName(RequisitionWkshName[2], ReqWkshTemplate[2].Name);
+
+        // [GIVEN] A requisition line exists in the first template's batch
+        RequisitionLine.Init();
+        RequisitionLine."Worksheet Template Name" := ReqWkshTemplate[1].Name;
+        RequisitionLine."Journal Batch Name" := RequisitionWkshName[1].Name;
+        RequisitionLine."Line No." := 10000;
+        RequisitionLine.Insert();
+
+        // [GIVEN] Current batch name is set to the second template's batch (simulating last used batch from different template)
+        CurrentJnlBatchName := RequisitionWkshName[2].Name;
+
+        // [GIVEN] A RequisitionLine record with template set directly on record (as when navigating from Item Availability by Event)
+        // The line has template name set directly but no filter on Journal Batch Name
+        RequisitionLine.Reset();
+        RequisitionLine."Worksheet Template Name" := ReqWkshTemplate[1].Name;
+        RequisitionLine."Journal Batch Name" := RequisitionWkshName[1].Name;
+        RequisitionLine.FilterGroup := 2;
+        RequisitionLine.SetRange("Worksheet Template Name", ReqWkshTemplate[1].Name);
+        RequisitionLine.FilterGroup := 0;
+        // Note: No filter on "Journal Batch Name" - this is the key condition for the fix
+
+        // [WHEN] OpenJnl is called
+        ReqJnlManagement.OpenJnl(CurrentJnlBatchName, RequisitionLine);
+
+        // [THEN] The current batch name should be the batch from the correct template
+        Assert.AreEqual(RequisitionWkshName[1].Name, CurrentJnlBatchName,
+            'OpenJnl should use the batch from the requisition line template, not the last used batch from different template');
+
+        // [THEN] The requisition line should be filtered to the correct batch
+        RequisitionLine.FilterGroup := 2;
+        Assert.AreEqual(RequisitionWkshName[1].Name, RequisitionLine.GetFilter("Journal Batch Name"),
+            'Requisition Line should be filtered to the correct batch in FilterGroup 2');
+    end;
 }

diff --git a/App/Layers/W1/Tests/SCM/SCMReservationEntryUT.Codeunit.al b/App/Layers/W1/Tests/SCM/SCMReservationEntryUT.Codeunit.al
new file mode 100644
index 00000000..bfd177b9
--- /dev/null
+++ b/App/Layers/W1/Tests/SCM/SCMReservationEntryUT.Codeunit.al
@@ -0,0 +1,142 @@
+codeunit 137822 "SCM Reservation Entry UT"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Reservation Entry] [SCM]
+    end;
+
+    var
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibraryUtility: Codeunit "Library - Utility";
+        isInitialized: Boolean;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure CalcReservationQuantityIncludesTrackingStatus()
+    var
+        ReservationEntry: array[3] of Record "Reservation Entry";
+        TotalQuantity: Decimal;
+        QtyPerUoM: Decimal;
+        BaseQty: Decimal;
+        ExpectedQty: Decimal;
+        SourceID: Code[20];
+        ItemNo: Code[20];
+    begin
+        // [FEATURE] [Reservation Entry] [Order Tracking]
+        // [SCENARIO 507858] When multiple tracking entries are split with fractional quantities,
+        // the Quantity field should sum correctly without rounding errors.
+        // BUG: Previously CalcReservationQuantity only considered Reservation status entries,
+        // not Tracking status entries, causing rounding errors when summing split tracking lines.
+        Initialize();
+
+        // [GIVEN] A UOM conversion of 6 base units per sales unit (Qty. per Unit of Measure = 6)
+        // With 3 entries of 28 base units each (total 84), each divided by 6 = 4.66667
+        // Without the fix, 4.66667 × 3 = 14.00001 (rounding error)
+        // With the fix, cumulative calculation ensures sum = 14 exactly
+        QtyPerUoM := 6;
+        BaseQty := -28; // Each entry has 28 base units (negative for demand)
+        ExpectedQty := 14; // 84 / 6 = 14 exactly
+
+        SourceID := LibraryUtility.GenerateGUID();
+        ItemNo := LibraryUtility.GenerateGUID();
+
+        // [GIVEN] Three reservation entries with Tracking status (from Order Tracking Policy)
+        CreateTrackingReservationEntry(ReservationEntry[1], ItemNo, SourceID, 1, BaseQty, QtyPerUoM);
+        CreateTrackingReservationEntry(ReservationEntry[2], ItemNo, SourceID, 1, BaseQty, QtyPerUoM);
+
+        // [WHEN] Validate Quantity (Base) on the third entry
+        // This triggers CalcReservationQuantity which should sum all related entries
+        CreateTrackingReservationEntry(ReservationEntry[3], ItemNo, SourceID, 1, BaseQty, QtyPerUoM);
+
+        // [THEN] The sum of Quantity fields should equal exactly -14 (without rounding errors)
+        ReservationEntry[1].Find();
+        ReservationEntry[2].Find();
+        ReservationEntry[3].Find();
+
+        TotalQuantity := ReservationEntry[1].Quantity + ReservationEntry[2].Quantity + ReservationEntry[3].Quantity;
+
+        // The total should be -14 (negative because demand)
+        // Without the fix this would be -14.00001 due to rounding of 4.66667 × 3
+        Assert.AreEqual(-ExpectedQty, TotalQuantity, 'Total Quantity must equal the expected sum without rounding errors');
+    end;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure CalcReservationQuantityWithReservationAndTrackingStatus()
+    var
+        ReservationEntry: Record "Reservation Entry";
+        TrackingEntry1: Record "Reservation Entry";
+        TrackingEntry2: Record "Reservation Entry";
+        TotalQuantity: Decimal;
+        QtyPerUoM: Decimal;
+        SourceID: Code[20];
+        ItemNo: Code[20];
+    begin
+        // [FEATURE] [Reservation Entry] [Order Tracking]
+        // [SCENARIO 507858] CalcReservationQuantity should include both Reservation and Tracking status entries
+        // when calculating the Quantity field from Quantity (Base).
+        Initialize();
+
+        // [GIVEN] A UOM conversion factor
+        QtyPerUoM := 24;
+        SourceID := LibraryUtility.GenerateGUID();
+        ItemNo := LibraryUtility.GenerateGUID();
+
+        // [GIVEN] One entry with Reservation status and one with Tracking status for the same source
+        CreateReservationEntryWithStatus(ReservationEntry, ItemNo, SourceID, 1, -144, QtyPerUoM, "Reservation Status"::Reservation);
+        CreateReservationEntryWithStatus(TrackingEntry1, ItemNo, SourceID, 1, -72, QtyPerUoM, "Reservation Status"::Tracking);
+
+        // [WHEN] A new Tracking entry is created and Quantity (Base) is validated
+        CreateReservationEntryWithStatus(TrackingEntry2, ItemNo, SourceID, 1, -72, QtyPerUoM, "Reservation Status"::Tracking);
+
+        // [THEN] The sum of all Quantity fields should equal exactly -12 (288 base / 24 = 12)
+        ReservationEntry.Find();
+        TrackingEntry1.Find();
+        TrackingEntry2.Find();
+
+        TotalQuantity := ReservationEntry.Quantity + TrackingEntry1.Quantity + TrackingEntry2.Quantity;
+
+        Assert.AreEqual(-12, TotalQuantity, 'Total Quantity must equal the expected sum including both Reservation and Tracking entries');
+    end;
+
+    local procedure Initialize()
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"SCM Reservation Entry UT");
+
+        if isInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"SCM Reservation Entry UT");
+
+        isInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"SCM Reservation Entry UT");
+    end;
+
+    local procedure CreateTrackingReservationEntry(var ReservationEntry: Record "Reservation Entry"; ItemNo: Code[20]; SourceID: Code[20]; SourceRefNo: Integer; QtyBase: Decimal; QtyPerUoM: Decimal)
+    begin
+        CreateReservationEntryWithStatus(ReservationEntry, ItemNo, SourceID, SourceRefNo, QtyBase, QtyPerUoM, "Reservation Status"::Tracking);
+    end;
+
+    local procedure CreateReservationEntryWithStatus(var ReservationEntry: Record "Reservation Entry"; ItemNo: Code[20]; SourceID: Code[20]; SourceRefNo: Integer; QtyBase: Decimal; QtyPerUoM: Decimal; ReservStatus: Enum "Reservation Status")
+    begin
+        ReservationEntry.Init();
+        ReservationEntry."Entry No." := LibraryUtility.GetNewRecNo(ReservationEntry, ReservationEntry.FieldNo("Entry No."));
+        ReservationEntry."Item No." := ItemNo;
+        ReservationEntry."Source Type" := Database::"Sales Line";
+        ReservationEntry."Source Subtype" := 1; // Order
+        ReservationEntry."Source ID" := SourceID;
+        ReservationEntry."Source Ref. No." := SourceRefNo;
+        ReservationEntry."Reservation Status" := ReservStatus;
+        ReservationEntry."Qty. per Unit of Measure" := QtyPerUoM;
+        ReservationEntry.Positive := QtyBase > 0;
+        ReservationEntry.Insert(true);
+
+        // Validate Quantity (Base) which triggers CalcReservationQuantity
+        ReservationEntry.Validate("Quantity (Base)", QtyBase);
+        ReservationEntry.Modify(true);
+    end;
+}

