diff --git a/test/SCMWarehousePutAwayBreakbulk.Codeunit.al b/test/SCMWarehousePutAwayBreakbulk.Codeunit.al
new file mode 100644
index 00000000..e3de43c2
--- /dev/null
+++ b/test/SCMWarehousePutAwayBreakbulk.Codeunit.al
@@ -0,0 +1,177 @@
+codeunit 137999 "SCM Whse Put-Away Breakbulk"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Warehouse] [Put-away] [Breakbulk]
+        isInitialized := false;
+    end;
+
+    var
+        LocationWhite: Record Location;
+        WarehouseEmployee: Record "Warehouse Employee";
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibraryWarehouse: Codeunit "Library - Warehouse";
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryPurchase: Codeunit "Library - Purchase";
+        LibraryRandom: Codeunit "Library - Random";
+        isInitialized: Boolean;
+
+    [Test]
+    [HandlerFunctions('ConfirmHandlerYes')]
+    [Scope('OnPrem')]
+    procedure RegisterPutAwayWithBreakbulkFilterRegistersAllLines()
+    var
+        Item: Record Item;
+        ItemUnitOfMeasure: Record "Item Unit of Measure";
+        PurchaseHeader: Record "Purchase Header";
+        WarehouseActivityHeader: Record "Warehouse Activity Header";
+        WarehouseActivityLine: Record "Warehouse Activity Line";
+        RegisteredWhseActivityLine: Record "Registered Whse. Activity Line";
+        WarehousePutAway: TestPage "Warehouse Put-away";
+        Quantity: Decimal;
+        QtyPerUOM: Decimal;
+        TotalLinesBeforeRegister: Integer;
+    begin
+        // [SCENARIO] When registering a put-away with Breakbulk Filter enabled, all put-away lines (including breakbulk lines) are registered
+        // [GIVEN] An item with a Put-away UOM (PCS) different from purchase UOM (BOX with Qty per UOM > 1)
+        Initialize();
+        Quantity := LibraryRandom.RandIntInRange(5, 10);
+        QtyPerUOM := LibraryRandom.RandIntInRange(5, 10);
+
+        LibraryInventory.CreateItem(Item);
+        CreateItemUnitOfMeasure(ItemUnitOfMeasure, Item."No.", QtyPerUOM);
+        UpdatePutAwayUnitOfMeasureOnItem(Item, Item."Base Unit of Measure");
+
+        // [GIVEN] A Purchase Order with the non-base UOM (BOX) is created and Warehouse Receipt is posted
+        // This creates Put-away lines with breakbulk lines (Take in BOX, Place in PCS)
+        CreatePurchaseOrderAndPostWarehouseReceipt(PurchaseHeader, LocationWhite.Code, Item."No.", Quantity, ItemUnitOfMeasure.Code);
+
+        // [GIVEN] Find the created Put-away
+        FindWarehouseActivityLine(
+            WarehouseActivityLine, WarehouseActivityLine."Source Document"::"Purchase Order",
+            PurchaseHeader."No.", WarehouseActivityLine."Activity Type"::"Put-away");
+        WarehouseActivityHeader.Get(WarehouseActivityLine."Activity Type", WarehouseActivityLine."No.");
+
+        // Count total lines before registration (including breakbulk lines)
+        WarehouseActivityLine.Reset();
+        WarehouseActivityLine.SetRange("Activity Type", WarehouseActivityHeader.Type);
+        WarehouseActivityLine.SetRange("No.", WarehouseActivityHeader."No.");
+        TotalLinesBeforeRegister := WarehouseActivityLine.Count();
+
+        // Verify we have breakbulk lines (more than 2 lines means breakbulk is involved)
+        Assert.IsTrue(TotalLinesBeforeRegister > 2, 'Expected breakbulk lines to be created');
+
+        // [GIVEN] Breakbulk Filter is set to Yes on the Put-away header
+        WarehouseActivityHeader.Validate("Breakbulk Filter", true);
+        WarehouseActivityHeader.Modify(true);
+
+        // [WHEN] Register the Put-away from the page with Breakbulk Filter enabled
+        WarehousePutAway.OpenEdit();
+        WarehousePutAway.Filter.SetFilter("No.", WarehouseActivityHeader."No.");
+        WarehousePutAway."&Register Put-away".Invoke();
+        WarehousePutAway.Close();
+
+        // [THEN] All put-away lines are registered (the put-away header should no longer exist)
+        Assert.IsFalse(WarehouseActivityHeader.Get(WarehouseActivityHeader.Type, WarehouseActivityHeader."No."),
+            'Warehouse Activity Header should be deleted after full registration');
+
+        // [THEN] All lines are registered as Registered Whse. Activity Lines
+        RegisteredWhseActivityLine.SetRange("Source Document", RegisteredWhseActivityLine."Source Document"::"Purchase Order");
+        RegisteredWhseActivityLine.SetRange("Source No.", PurchaseHeader."No.");
+        RegisteredWhseActivityLine.SetRange("Activity Type", RegisteredWhseActivityLine."Activity Type"::"Put-away");
+        Assert.AreEqual(TotalLinesBeforeRegister, RegisteredWhseActivityLine.Count(),
+            'All put-away lines including breakbulk lines should be registered');
+    end;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"SCM Whse Put-Away Breakbulk");
+
+        if isInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"SCM Whse Put-Away Breakbulk");
+
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        LibraryERMCountryData.UpdateVATPostingSetup();
+        LibraryERMCountryData.CreateVATData();
+
+        CreateLocationSetup();
+        NoSeriesSetup();
+
+        isInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"SCM Whse Put-Away Breakbulk");
+    end;
+
+    local procedure NoSeriesSetup()
+    var
+        WarehouseSetup: Record "Warehouse Setup";
+    begin
+        LibraryWarehouse.NoSeriesSetup(WarehouseSetup);
+        LibraryPurchase.SetOrderNoSeriesInSetup();
+    end;
+
+    local procedure CreateLocationSetup()
+    begin
+        LibraryWarehouse.CreateFullWMSLocation(LocationWhite, 2);
+        LibraryWarehouse.CreateWarehouseEmployee(WarehouseEmployee, LocationWhite.Code, true);
+    end;
+
+    local procedure CreateItemUnitOfMeasure(var ItemUnitOfMeasure: Record "Item Unit of Measure"; ItemNo: Code[20]; QtyPerUOM: Decimal)
+    begin
+        LibraryInventory.CreateItemUnitOfMeasureCode(ItemUnitOfMeasure, ItemNo, QtyPerUOM);
+    end;
+
+    local procedure UpdatePutAwayUnitOfMeasureOnItem(var Item: Record Item; UnitOfMeasureCode: Code[10])
+    begin
+        Item.Validate("Put-away Unit of Measure Code", UnitOfMeasureCode);
+        Item.Modify(true);
+    end;
+
+    local procedure CreatePurchaseOrderAndPostWarehouseReceipt(var PurchaseHeader: Record "Purchase Header"; LocationCode: Code[10]; ItemNo: Code[20]; Quantity: Decimal; UnitOfMeasureCode: Code[10])
+    var
+        PurchaseLine: Record "Purchase Line";
+        WarehouseReceiptHeader: Record "Warehouse Receipt Header";
+        WarehouseReceiptLine: Record "Warehouse Receipt Line";
+    begin
+        LibraryPurchase.CreatePurchHeader(PurchaseHeader, PurchaseHeader."Document Type"::Order, '');
+        LibraryPurchase.CreatePurchaseLine(PurchaseLine, PurchaseHeader, PurchaseLine.Type::Item, ItemNo, Quantity);
+        PurchaseLine.Validate("Location Code", LocationCode);
+        PurchaseLine.Validate("Unit of Measure Code", UnitOfMeasureCode);
+        PurchaseLine.Modify(true);
+        LibraryPurchase.ReleasePurchaseDocument(PurchaseHeader);
+
+        LibraryWarehouse.CreateWhseReceiptFromPO(PurchaseHeader);
+        FindWarehouseReceiptLine(WarehouseReceiptLine, WarehouseReceiptLine."Source Document"::"Purchase Order", PurchaseHeader."No.", LocationCode);
+        WarehouseReceiptHeader.Get(WarehouseReceiptLine."No.");
+        LibraryWarehouse.PostWhseReceipt(WarehouseReceiptHeader);
+    end;
+
+    local procedure FindWarehouseReceiptLine(var WarehouseReceiptLine: Record "Warehouse Receipt Line"; SourceDocument: Enum "Warehouse Activity Source Document"; SourceNo: Code[20]; LocationCode: Code[10])
+    begin
+        WarehouseReceiptLine.SetRange("Source Document", SourceDocument);
+        WarehouseReceiptLine.SetRange("Source No.", SourceNo);
+        WarehouseReceiptLine.SetRange("Location Code", LocationCode);
+        WarehouseReceiptLine.FindFirst();
+    end;
+
+    local procedure FindWarehouseActivityLine(var WarehouseActivityLine: Record "Warehouse Activity Line"; SourceDocument: Enum "Warehouse Activity Source Document"; SourceNo: Code[20]; ActivityType: Enum "Warehouse Activity Type")
+    begin
+        WarehouseActivityLine.SetRange("Source Document", SourceDocument);
+        WarehouseActivityLine.SetRange("Source No.", SourceNo);
+        WarehouseActivityLine.SetRange("Activity Type", ActivityType);
+        WarehouseActivityLine.FindFirst();
+    end;
+
+    [ConfirmHandler]
+    procedure ConfirmHandlerYes(Question: Text[1024]; var Reply: Boolean)
+    begin
+        Reply := true;
+    end;
+}

