+        // [SCENARIO 548932] Stan can post multiple general journal lines with the same Document No. and Posting Date when incoming document is attached to only one line
+        // [SCENARIO] This verifies that incoming documents are synced between lines with the same Document No. and Posting Date
+
+        Initialize();
+        BindSubscription(DigVouchersDisableEnforce);
+        // [GIVEN] Digital voucher entry setup for general journal is "Attachment" and "Generate Automatically" is NOT enabled
+        InitSetupCheckOnly("Digital Voucher Entry Type"::"General Journal", "Digital Voucher Check Type"::Attachment);
+        // [GIVEN] General journal template with "Force Doc. Balance" = false
+        LibraryERM.CreateGenJournalTemplate(GenJournalTemplate);
+        GenJournalTemplate.Validate("Force Doc. Balance", false);
+        GenJournalTemplate.Modify(true);
+        LibraryERM.CreateGenJournalBatch(GenJournalBatch, GenJournalTemplate.Name);
+        // [GIVEN] Two general journal lines with the same "Document No." and "Posting Date"
+        // [GIVEN] Line 1: Debit 100
+        // [GIVEN] Line 2: Credit -100
+        Amount := LibraryRandom.RandDec(100, 2);
+        DocNo := LibraryUtility.GenerateGUID();
+        LibraryJournals.CreateGenJournalLine(
+            GenJournalLine[1], GenJournalTemplate.Name, GenJournalBatch.Name,
+            GenJournalLine[1]."Document Type"::" ", GenJournalLine[1]."Account Type"::"G/L Account",
+            LibraryERM.CreateGLAccountNo(), GenJournalLine[1]."Bal. Account Type"::"G/L Account",
+            '', Amount);
+        GenJournalLine[1].Validate("Document No.", DocNo);
+        GenJournalLine[1].Modify(true);
+        LibraryJournals.CreateGenJournalLine(
+            GenJournalLine[2], GenJournalTemplate.Name, GenJournalBatch.Name,
+            GenJournalLine[2]."Document Type"::" ", GenJournalLine[2]."Account Type"::"G/L Account",
+            LibraryERM.CreateGLAccountNo(), GenJournalLine[2]."Bal. Account Type"::"G/L Account",
+            '', -Amount);
+        GenJournalLine[2].Validate("Document No.", DocNo);
+        GenJournalLine[2].Validate("Posting Date", GenJournalLine[1]."Posting Date");
+        GenJournalLine[2].Modify(true);
+        // [GIVEN] Incoming document is attached ONLY to line 1
+        GenJournalLine[1].Validate("Incoming Document Entry No.", MockIncomingDocument(GenJournalLine[1]."Posting Date", GenJournalLine[1]."Document No."));
+        GenJournalLine[1].Modify(true);
+
+        // [WHEN] Post both general journal lines
+        GenJournalLineToPost.SetRange("Journal Template Name", GenJournalTemplate.Name);
+        GenJournalLineToPost.SetRange("Journal Batch Name", GenJournalBatch.Name);
+        GenJournalLineToPost.FindSet();
+        Codeunit.Run(Codeunit::"Gen. Jnl.-Post Batch", GenJournalLineToPost);
+
+        // [THEN] Both lines are posted without error because the incoming document on line 1 is shared with line 2
+        // [THEN] No error "Not possible to post without attaching the digital voucher" is raised
+        GenJournalLine[1].SetRange("Journal Template Name", GenJournalTemplate.Name);
+        GenJournalLine[1].SetRange("Journal Batch Name", GenJournalBatch.Name);
+        Assert.RecordIsEmpty(GenJournalLine[1]);
+
+        UnbindSubscription(DigVouchersDisableEnforce);
+    end;
+
