@@ -0,0 +1,80 @@
+codeunit 139614 "Shpfy Copy Document Test"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    var
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryRandom: Codeunit "Library - Random";
+        LibraryAssert: Codeunit "Library Assert";
+
+    [Test]
+    procedure CopyPostedInvoiceClearsShopifyOrderId()
+    var
+        SalesHeader: Record "Sales Header";
+        SalesInvoiceHeader: Record "Sales Invoice Header";
+        CopyDocumentMgt: Codeunit "Copy Document Mgt.";
+        SalesDocumentTypeFrom: Enum "Sales Document Type From";
+        ShpfyOrderId: BigInteger;
+        ShpfyOrderNo: Code[50];
+        ShpfyRefundId: BigInteger;
+    begin
+        // [SCENARIO] When copying a posted sales invoice with Shopify Order Id to a new invoice, 
+        // the Shopify Order Id, Order No., and Refund Id should be cleared on the new document.
+
+        // [GIVEN] A posted sales invoice with Shopify Order Id, Order No., and Refund Id populated
+        ShpfyOrderId := LibraryRandom.RandIntInRange(100000, 999999);
+        ShpfyOrderNo := CopyStr(LibraryRandom.RandText(10), 1, MaxStrLen(ShpfyOrderNo));
+        ShpfyRefundId := LibraryRandom.RandIntInRange(100000, 999999);
+        CreateAndPostSalesInvoiceWithShopifyData(SalesInvoiceHeader, ShpfyOrderId, ShpfyOrderNo, ShpfyRefundId);
+
+        // [GIVEN] A new sales invoice to copy to
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Invoice, SalesInvoiceHeader."Sell-to Customer No.");
+
+        // [WHEN] The posted invoice is copied with Include Header = true
+        CopyDocumentMgt.SetProperties(true, false, false, false, false, false, false);
+        CopyDocumentMgt.CopySalesDoc(SalesDocumentTypeFrom::"Posted Invoice", SalesInvoiceHeader."No.", SalesHeader);
+
+        // [THEN] The new sales invoice has Shopify Order Id cleared
+        SalesHeader.Get(SalesHeader."Document Type", SalesHeader."No.");
+        LibraryAssert.AreEqual(0, SalesHeader."Shpfy Order Id", 'Shpfy Order Id should be cleared after copying from posted invoice');
+
+        // [THEN] The new sales invoice has Shopify Order No. cleared
+        LibraryAssert.AreEqual('', SalesHeader."Shpfy Order No.", 'Shpfy Order No. should be cleared after copying from posted invoice');
+
+        // [THEN] The new sales invoice has Shopify Refund Id cleared
+        LibraryAssert.AreEqual(0, SalesHeader."Shpfy Refund Id", 'Shpfy Refund Id should be cleared after copying from posted invoice');
+    end;
+
+    local procedure CreateAndPostSalesInvoiceWithShopifyData(var SalesInvoiceHeader: Record "Sales Invoice Header"; ShpfyOrderId: BigInteger; ShpfyOrderNo: Code[50]; ShpfyRefundId: BigInteger)
+    var
+        Customer: Record Customer;
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        PostedDocNo: Code[20];
+    begin
+        LibrarySales.CreateCustomer(Customer);
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Invoice, Customer."No.");
+        LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::"G/L Account", CreateGLAccount(), 1);
+        SalesLine.Validate("Unit Price", LibraryRandom.RandDecInRange(10, 100, 2));
+        SalesLine.Modify(true);
+
+        PostedDocNo := LibrarySales.PostSalesDocument(SalesHeader, false, true);
+
+        SalesInvoiceHeader.Get(PostedDocNo);
+        SalesInvoiceHeader."Shpfy Order Id" := ShpfyOrderId;
+        SalesInvoiceHeader."Shpfy Order No." := ShpfyOrderNo;
+        SalesInvoiceHeader.Modify();
+    end;
+
+    local procedure CreateGLAccount(): Code[20]
+    var
+        GLAccount: Record "G/L Account";
+        LibraryERM: Codeunit "Library - ERM";
+    begin
+        LibraryERM.CreateGLAccount(GLAccount);
+        GLAccount."Direct Posting" := true;
+        GLAccount.Modify();
+        exit(GLAccount."No.");
+    end;
+}

