+
+    [Test]
+    [HandlerFunctions('MessageHandler,ItemTrackingLinesWithExpirationPageHandler')]
+    [Scope('OnPrem')]
+    procedure InvtPickFEFOWithMultipleBinsAndLotsRoundingCorrection()
+    var
+        Location: Record Location;
+        Bin: array[3] of Record Bin;
+        Item: Record Item;
+        ItemUnitOfMeasure: Record "Item Unit of Measure";
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
