+    begin
+        // [FEATURE] [Inventory Pick] [FEFO] [Rounding] [Item Tracking]
+        // [SCENARIO] Creating inventory pick with FEFO and multiple lots with expiration dates across different bins
+        // should not have rounding issues when using a non-base UOM with fractional Qty. per Unit of Measure.
+        Initialize();
+
+        // [GIVEN] Location with Require Pick = Yes and Pick According to FEFO = Yes with multiple bins
+        CreateFEFOLocationWithBins(Location, Bin);
+
+        // [GIVEN] Item with lot tracking and expiration date tracking
+        CreateItemWithLotAndExpirationTracking(Item);
+
+        // [GIVEN] Non-base UOM 'PACK' with Qty. per Unit of Measure = 2.888 and Qty. Rounding Precision = 0.00001
+        QtyPerUOM := 2.888;
+        LibraryInventory.CreateUnitOfMeasureCode(UnitOfMeasure);
+        LibraryInventory.CreateItemUnitOfMeasure(ItemUnitOfMeasure, Item."No.", UnitOfMeasure.Code, QtyPerUOM);
+        ItemUnitOfMeasure."Qty. Rounding Precision" := 0.00001;
+        ItemUnitOfMeasure.Modify();
