+        // Bin 3: LOT02 (16.05.2025): 1.78787 PCS, LOT03 (25.09.2025): 42.73313 PCS, LOT05 (13.07.2025): 4.013 PCS
+        PostInventoryWithLotAndExpiration(Item."No.", Location.Code, Bin[1].Code, 'LOT01', 434.97616, CalcDate('<+10M>', WorkDate()));
+        PostInventoryWithLotAndExpiration(Item."No.", Location.Code, Bin[1].Code, 'LOT03', 17.3126, CalcDate('<+8M>', WorkDate()));
+        PostInventoryWithLotAndExpiration(Item."No.", Location.Code, Bin[1].Code, 'LOT06', 17.0373, CalcDate('<+8M>', WorkDate()));
+        PostInventoryWithLotAndExpiration(Item."No.", Location.Code, Bin[2].Code, 'LOT01', 4.13394, CalcDate('<+8M>', WorkDate()));
+        PostInventoryWithLotAndExpiration(Item."No.", Location.Code, Bin[2].Code, 'LOT02', 4.34355, CalcDate('<+10M>', WorkDate()));
+        PostInventoryWithLotAndExpiration(Item."No.", Location.Code, Bin[2].Code, 'LOT03', 151.33333, CalcDate('<+8M>', WorkDate()));
+        PostInventoryWithLotAndExpiration(Item."No.", Location.Code, Bin[2].Code, 'LOT04', 40.01221, CalcDate('<+5M>', WorkDate()));
+        PostInventoryWithLotAndExpiration(Item."No.", Location.Code, Bin[3].Code, 'LOT02', 1.78787, CalcDate('<+4M>', WorkDate()));
+        PostInventoryWithLotAndExpiration(Item."No.", Location.Code, Bin[3].Code, 'LOT03', 42.73313, CalcDate('<+8M>', WorkDate()));
+        PostInventoryWithLotAndExpiration(Item."No.", Location.Code, Bin[3].Code, 'LOT05', 4.013, CalcDate('<+6M>', WorkDate()));
+
+        // [GIVEN] Sales Order with Quantity = 248 PACK = 716.224 PCS (248 * 2.888)
+        SalesQty := 248;
+        ExpectedSalesQtyBase := SalesQty * QtyPerUOM; // 716.224
+        CreateSalesOrderWithUOM(SalesHeader, SalesLine, Item."No.", Location.Code, SalesQty, UnitOfMeasure.Code);
+
+        // [WHEN] Create Inventory Pick
+        LibraryVariableStorage.Enqueue(NoOfPicksCreatedMsg);
+        LibrarySales.ReleaseSalesDocument(SalesHeader);
+        SalesHeader.CreateInvtPutAwayPick();
+
+        // [THEN] The sum of Quantity on the pick lines equals the full ordered quantity (248 PACK)
+        WarehouseActivityLine.SetRange("Source Type", Database::"Sales Line");
+        WarehouseActivityLine.SetRange("Source No.", SalesHeader."No.");
+        WarehouseActivityLine.SetRange("Activity Type", WarehouseActivityLine."Activity Type"::"Invt. Pick");
+        WarehouseActivityLine.CalcSums(Quantity);
+        TotalPickQty := WarehouseActivityLine.Quantity;
+
+        Assert.AreEqual(SalesQty, TotalPickQty,
+            'The sum of pick line quantities should equal the ordered quantity without rounding loss');
+
+        // [THEN] Verify the total base quantity also matches expected
+        WarehouseActivityLine.CalcSums("Qty. (Base)");
+        Assert.AreNearlyEqual(ExpectedSalesQtyBase, WarehouseActivityLine."Qty. (Base)", 0.00001,
+            'The sum of pick line base quantities should equal the ordered base quantity');
+    end;
+
