+    local procedure CreateSalesOrderWithUOM(var SalesHeader: Record "Sales Header"; var SalesLine: Record "Sales Line"; ItemNo: Code[20]; LocationCode: Code[10]; Qty: Decimal; UOMCode: Code[10])
