diff --git a/App/Layers/W1/Tests/SCM/SCMPlanningMultiLevelBOM.Codeunit.al b/App/Layers/W1/Tests/SCM/SCMPlanningMultiLevelBOM.Codeunit.al
new file mode 100644
index 00000000..feda7dc9
--- /dev/null
+++ b/App/Layers/W1/Tests/SCM/SCMPlanningMultiLevelBOM.Codeunit.al
@@ -0,0 +1,168 @@
+codeunit 137690 "SCM Planning Multi Level BOM"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Planning] [Planning Worksheet] [SCM]
+        isInitialized := false;
+    end;
+
+    var
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryPlanning: Codeunit "Library - Planning";
+        LibraryManufacturing: Codeunit "Library - Manufacturing";
+        LibraryRandom: Codeunit "Library - Random";
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibrarySetupStorage: Codeunit "Library - Setup Storage";
+        isInitialized: Boolean;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure CalcRegenPlanNoReqLinesForComponentUsedInMultipleSubassemblies()
+    var
+        Item1: Record Item;
+        Item2A: Record Item;
+        Item2B: Record Item;
+        Item3: Record Item;
+        ProductionOrder: Record "Production Order";
+        RequisitionLine: Record "Requisition Line";
+        ProductionBOMHeaderLevel1: Record "Production BOM Header";
+        ProductionBOMHeaderLevel2A: Record "Production BOM Header";
+        ProductionBOMHeaderLevel2B: Record "Production BOM Header";
+    begin
+        // [SCENARIO 475000] When running planning worksheet for an item consumed in multiple subassemblies,
+        // no unnecessary requisition lines should be suggested if demand and supply quantities are equal.
+
+        // [GIVEN] Items Item1, Item2A, Item2B, Item3 with Replenishment: Prod Order, Manufacturing Policy: Make-to-Order, Reordering Policy: Lot-for-Lot
+        Initialize();
+
+        // [GIVEN] Item3 - lowest level item (component)
+        CreateMakeToOrderProdItem(Item3);
+
+        // [GIVEN] Item2A and Item2B - middle level items, both use Item3 as component
+        CreateMakeToOrderProdItem(Item2A);
+        CreateAndCertifyProductionBOM(ProductionBOMHeaderLevel2A, Item3."No.", Item3."Base Unit of Measure", 1);
+        UpdateProductionBOMNoOnItem(Item2A, ProductionBOMHeaderLevel2A."No.");
+
+        CreateMakeToOrderProdItem(Item2B);
+        CreateAndCertifyProductionBOM(ProductionBOMHeaderLevel2B, Item3."No.", Item3."Base Unit of Measure", 1);
+        UpdateProductionBOMNoOnItem(Item2B, ProductionBOMHeaderLevel2B."No.");
+
+        // [GIVEN] Item1 - top level item, uses Item2A and Item2B as components
+        CreateMakeToOrderProdItem(Item1);
+        CreateAndCertifyProductionBOMWithTwoComponents(
+            ProductionBOMHeaderLevel1, Item2A."No.", Item2B."No.", Item1."Base Unit of Measure", 1);
+        UpdateProductionBOMNoOnItem(Item1, ProductionBOMHeaderLevel1."No.");
+
+        // [GIVEN] Calculate Low-Level Code to update BOM hierarchy
+        LibraryPlanning.CalculateLowLevelCode();
+
+        // [GIVEN] Released Production Order for Item1 with Quantity = 1, refreshed
+        // This creates demand for Item3 with quantity = 2 (one from Item2A and one from Item2B)
+        LibraryManufacturing.CreateAndRefreshProductionOrder(
+            ProductionOrder,
+            ProductionOrder.Status::Released,
+            ProductionOrder."Source Type"::Item,
+            Item1."No.",
+            1);
+
+        // [WHEN] Calculate Regenerative Plan for Item3
+        Item3.SetRecFilter();
+        LibraryPlanning.CalcRegenPlanForPlanWksh(Item3, WorkDate(), CalcDate('<+1Y>', WorkDate()));
+
+        // [THEN] No requisition lines should be created for Item3 because supply (from prod. order line) equals demand (from prod. order components)
+        RequisitionLine.SetRange(Type, RequisitionLine.Type::Item);
+        RequisitionLine.SetRange("No.", Item3."No.");
+        Assert.RecordIsEmpty(RequisitionLine);
+    end;
+
+    local procedure Initialize()
+    var
+        RequisitionLine: Record "Requisition Line";
+        ReservationEntry: Record "Reservation Entry";
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(CODEUNIT::"SCM Planning Multi Level BOM");
+        LibrarySetupStorage.Restore();
+        RequisitionLine.DeleteAll();
+        ReservationEntry.DeleteAll();
+        LibraryRandom.Init();
+
+        // Lazy Setup.
+        if isInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(CODEUNIT::"SCM Planning Multi Level BOM");
+
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        UpdateCombinedMPSMRPCalculation(true);
+        DisableManufacturingPlanningWarning();
+
+        LibrarySetupStorage.Save(DATABASE::"Inventory Setup");
+        LibrarySetupStorage.Save(DATABASE::"Manufacturing Setup");
+
+        isInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(CODEUNIT::"SCM Planning Multi Level BOM");
+    end;
+
+    local procedure CreateMakeToOrderProdItem(var Item: Record Item)
+    begin
+        LibraryInventory.CreateItem(Item);
+        Item.Validate("Replenishment System", Item."Replenishment System"::"Prod. Order");
+        Item.Validate("Reordering Policy", Item."Reordering Policy"::"Lot-for-Lot");
+        Item.Validate("Manufacturing Policy", Item."Manufacturing Policy"::"Make-to-Order");
+        Item.Modify(true);
+    end;
+
+    local procedure CreateAndCertifyProductionBOM(var ProductionBOMHeader: Record "Production BOM Header"; ComponentItemNo: Code[20]; UnitOfMeasureCode: Code[10]; QuantityPer: Decimal)
+    var
+        ProductionBOMLine: Record "Production BOM Line";
+    begin
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader, UnitOfMeasureCode);
+        LibraryManufacturing.CreateProductionBOMLine(
+            ProductionBOMHeader, ProductionBOMLine, '', ProductionBOMLine.Type::Item, ComponentItemNo, QuantityPer);
+        ProductionBOMHeader.Validate(Status, ProductionBOMHeader.Status::Certified);
+        ProductionBOMHeader.Modify(true);
+    end;
+
+    local procedure CreateAndCertifyProductionBOMWithTwoComponents(var ProductionBOMHeader: Record "Production BOM Header"; ComponentItemNo1: Code[20]; ComponentItemNo2: Code[20]; UnitOfMeasureCode: Code[10]; QuantityPer: Decimal)
+    var
+        ProductionBOMLine: Record "Production BOM Line";
+    begin
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader, UnitOfMeasureCode);
+        LibraryManufacturing.CreateProductionBOMLine(
+            ProductionBOMHeader, ProductionBOMLine, '', ProductionBOMLine.Type::Item, ComponentItemNo1, QuantityPer);
+        LibraryManufacturing.CreateProductionBOMLine(
+            ProductionBOMHeader, ProductionBOMLine, '', ProductionBOMLine.Type::Item, ComponentItemNo2, QuantityPer);
+        ProductionBOMHeader.Validate(Status, ProductionBOMHeader.Status::Certified);
+        ProductionBOMHeader.Modify(true);
+    end;
+
+    local procedure UpdateProductionBOMNoOnItem(var Item: Record Item; ProductionBOMNo: Code[20])
+    begin
+        Item.Validate("Production BOM No.", ProductionBOMNo);
+        Item.Modify(true);
+    end;
+
+    local procedure UpdateCombinedMPSMRPCalculation(NewValue: Boolean)
+    var
+        InventorySetup: Record "Inventory Setup";
+    begin
+        InventorySetup.Get();
+        InventorySetup.Validate("Combined MPS/MRP Calculation", NewValue);
+        InventorySetup.Modify(true);
+    end;
+
+    local procedure DisableManufacturingPlanningWarning()
+    var
+        ManufacturingSetup: Record "Manufacturing Setup";
+    begin
+        ManufacturingSetup.Get();
+        ManufacturingSetup.Validate("Planning Warning", false);
+        ManufacturingSetup.Modify(true);
+    end;
+}

