+        FindWarehouseShipmentHeader(WarehouseShipmentHeader, SalesHeader[2]."No.", WarehouseShipmentLine."Source Document"::"Sales Order");
+
+        // [GIVEN] Create pick for the warehouse shipment for the second sales order.
