+        ItemLedgerEntry: Record "Item Ledger Entry";
+        LotNo: Code[50];
+        Qty1: Decimal;
+        Qty2: Decimal;
+        Qty3: Decimal;
+        TotalQty: Decimal;
+    begin
+        // [FEATURE] [Consumption] [Item Tracking] [Reservation]
+        // [SCENARIO] Posting consumption that is reserved to multiple lot-tracked ILEs with the same lot number should succeed.
+        // Bug: When item with Reserve = Always is lot-tracked and has multiple ILEs with same lot number,
+        // posting full consumption fails with "You have insufficient quantity of Item on Inventory" error.
+        Initialize();
+
+        // [GIVEN] Lot-tracked component item "C" with Reserve = Always, Manual flushing
+        LibraryItemTracking.CreateItemTrackingCode(ItemTrackingCode, false, true);
+        LibraryInventory.CreateItem(CompItem);
+        CompItem.Validate("Item Tracking Code", ItemTrackingCode.Code);
+        CompItem.Validate("Lot Nos.", LibraryUtility.GetGlobalNoSeriesCode());
+        CompItem.Validate(Reserve, CompItem.Reserve::Always);
+        CompItem.Validate("Flushing Method", CompItem."Flushing Method"::Manual);
+        CompItem.Modify(true);
+
+        // [GIVEN] Parent item "P" that consumes component "C" in its production BOM (quantity per = 1)
+        LibraryInventory.CreateItem(ProdItem);
+        ProdItem.Validate("Replenishment System", ProdItem."Replenishment System"::"Prod. Order");
+        ProdItem.Modify(true);
+        CreateCertifiedProductionBOMWithQtyPer(ProductionBOMHeader, CompItem."No.", ProdItem."Base Unit of Measure", 1);
+        UpdateProductionBOMOnItem(ProdItem, ProductionBOMHeader."No.");
+
+        // [GIVEN] 3 positive adjustments creating 3 ILEs with same lot number "LOTX" for quantities 5, 10, 20 (total = 35)
+        Qty1 := 5;
+        Qty2 := 10;
+        Qty3 := 20;
+        TotalQty := Qty1 + Qty2 + Qty3;
+        LotNo := LibraryUtility.GenerateGUID();
+
+        CreateAndPostItemJournalLineWithLotNo(CompItem."No.", LocationBlue.Code, Qty1, LotNo);
+        CreateAndPostItemJournalLineWithLotNo(CompItem."No.", LocationBlue.Code, Qty2, LotNo);
+        CreateAndPostItemJournalLineWithLotNo(CompItem."No.", LocationBlue.Code, Qty3, LotNo);
+
+        // [GIVEN] Released production order for 35 qty of parent item "P" at BLUE location
+        LibraryManufacturing.CreateProductionOrder(
+            ProductionOrder, ProductionOrder.Status::Released, ProductionOrder."Source Type"::Item, ProdItem."No.", TotalQty);
+        ProductionOrder.Validate("Location Code", LocationBlue.Code);
+        ProductionOrder.Modify(true);
+        LibraryManufacturing.RefreshProdOrder(ProductionOrder, false, true, true, true, false);
+
+        // [GIVEN] Component is auto-reserved to the 3 ILEs due to Reserve = Always
+        FindProdOrderComponent(ProdOrderComponent, ProductionOrder.Status, ProductionOrder."No.", CompItem."No.");
+        ProdOrderComponent.CalcFields("Reserved Quantity");
+        Assert.AreEqual(TotalQty, ProdOrderComponent."Reserved Quantity", 'Component should be fully reserved.');
+
+        // [WHEN] Create consumption journal line with item tracking for lot "LOTX" for full 35 qty and post
+        LibraryInventory.ClearItemJournal(ConsumptionItemJournalTemplate, ConsumptionItemJournalBatch);
+        LibraryInventory.CreateItemJournalLine(
+            ItemJournalLine, ConsumptionItemJournalTemplate.Name, ConsumptionItemJournalBatch.Name,
+            ItemJournalLine."Entry Type"::Consumption, CompItem."No.", TotalQty);
+        ItemJournalLine.Validate("Order No.", ProductionOrder."No.");
+        ItemJournalLine.Validate("Location Code", LocationBlue.Code);
+        ItemJournalLine.Modify(true);
+
+        LibraryVariableStorage.Enqueue(ItemTrackingMode::"Set Quantity & Lot No.");
+        LibraryVariableStorage.Enqueue(LotNo);
+        LibraryVariableStorage.Enqueue(TotalQty);
+        ItemJournalLine.OpenItemTrackingLines(false);
+
+        // Posting should succeed (before fix it failed with "insufficient quantity" error)
+        LibraryInventory.PostItemJournalLine(ItemJournalLine."Journal Template Name", ItemJournalLine."Journal Batch Name");
+
+        // [THEN] Consumption entry is posted for 35 qty
+        ItemLedgerEntry.SetRange("Item No.", CompItem."No.");
+        ItemLedgerEntry.SetRange("Entry Type", ItemLedgerEntry."Entry Type"::Consumption);
+        ItemLedgerEntry.SetRange("Order No.", ProductionOrder."No.");
+        ItemLedgerEntry.CalcSums(Quantity);
+        Assert.AreEqual(-TotalQty, ItemLedgerEntry.Quantity, 'Consumption should be posted for full quantity.');
+
+        LibraryVariableStorage.AssertEmpty();
+    end;
+
+    local procedure CreateAndPostItemJournalLineWithLotNo(ItemNo: Code[20]; LocationCode: Code[10]; Qty: Decimal; LotNo: Code[50])
+    var
+        ItemJournalLine: Record "Item Journal Line";
+        ReservEntry: Record "Reservation Entry";
+    begin
+        LibraryInventory.ClearItemJournal(ItemJournalTemplate, ItemJournalBatch);
+        LibraryInventory.CreateItemJournalLine(
+            ItemJournalLine, ItemJournalBatch."Journal Template Name", ItemJournalBatch.Name,
+            ItemJournalLine."Entry Type"::"Positive Adjmt.", ItemNo, Qty);
+        ItemJournalLine.Validate("Location Code", LocationCode);
+        ItemJournalLine.Modify(true);
+
+        LibraryItemTracking.CreateItemJournalLineItemTracking(ReservEntry, ItemJournalLine, '', LotNo, Qty);
+
+        LibraryInventory.PostItemJournalLine(ItemJournalLine."Journal Template Name", ItemJournalLine."Journal Batch Name");
+    end;
+
+    local procedure CreateCertifiedProductionBOMWithQtyPer(var ProductionBOMHeader: Record "Production BOM Header"; ItemNo: Code[20]; BaseUnitOfMeasure: Code[10]; QtyPer: Decimal)
+    var
+        ProductionBOMLine: Record "Production BOM Line";
+    begin
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader, BaseUnitOfMeasure);
+        LibraryManufacturing.CreateProductionBOMLine(ProductionBOMHeader, ProductionBOMLine, '', ProductionBOMLine.Type::Item, ItemNo, QtyPer);
+        ProductionBOMHeader.Validate(Status, ProductionBOMHeader.Status::Certified);
+        ProductionBOMHeader.Modify(true);
+    end;
+
     local procedure Initialize()
     var
         LibraryERMCountryData: Codeunit "Library - ERM Country Data";

