diff --git a/App/Apps/W1/ExcelReports/test/src/FixedAssetExcelReports.Codeunit.al b/App/Apps/W1/ExcelReports/test/src/FixedAssetExcelReports.Codeunit.al
new file mode 100644
index 00000000..2ef82aad
--- /dev/null
+++ b/App/Apps/W1/ExcelReports/test/src/FixedAssetExcelReports.Codeunit.al
@@ -0,0 +1,93 @@
+namespace Microsoft.Finance.ExcelReports.Test;
+
+using Microsoft.Finance.ExcelReports;
+using Microsoft.FixedAssets.FixedAsset;
+using Microsoft.FixedAssets.Depreciation;
+using Microsoft.FixedAssets.Posting;
+using Microsoft.FixedAssets.Setup;
+
+codeunit 139545 "Fixed Asset Excel Reports"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    var
+        LibraryFixedAsset: Codeunit "Library - Fixed Asset";
+        LibraryReportDataset: Codeunit "Library - Report Dataset";
+        Assert: Codeunit Assert;
+
+    [Test]
+    [HandlerFunctions('EXRFixedAssetAnalysisExcelHandler')]
+    procedure FixedAssetAnalysisExportsAcquisitionDate()
+    var
+        FixedAsset: Record "Fixed Asset";
+        FADepreciationBook: Record "FA Depreciation Book";
+        DepreciationBook: Record "Depreciation Book";
+        FAPostingType: Record "FA Posting Type";
+        Variant: Variant;
+        AcquisitionDate: Date;
+        RequestPageXml: Text;
+    begin
+        // [SCENARIO] The Fixed Asset Analysis Excel report should include Acquisition Date for acquired Fixed Assets
+        // [GIVEN] A Fixed Asset with a depreciation book and acquisition date set
+        CleanUpFixedAssetData();
+        CreateFixedAssetWithAcquisitionDate(FixedAsset, FADepreciationBook, DepreciationBook, WorkDate());
+        Commit();
+
+        // [WHEN] Running the Fixed Asset Analysis Excel report
+        RequestPageXml := Report.RunRequestPage(Report::"EXR Fixed Asset Analysis Excel", RequestPageXml);
+        LibraryReportDataset.RunReportAndLoad(Report::"EXR Fixed Asset Analysis Excel", Variant, RequestPageXml);
+
+        // [THEN] The Acquisition Date should be populated in the report output
+        LibraryReportDataset.SetXmlNodeList('DataItem[@name="FAPostingType"]');
+        Assert.IsTrue(LibraryReportDataset.RowCount() > 0, 'FA Posting Type rows should be exported');
+        LibraryReportDataset.GetNextRow();
+        LibraryReportDataset.FindCurrentRowValue('AcquisitionDateField', Variant);
+        AcquisitionDate := Variant;
+        Assert.AreEqual(WorkDate(), AcquisitionDate, 'The Acquisition Date should be populated with the correct value');
+    end;
+
+    local procedure CleanUpFixedAssetData()
+    var
+        FAPostingType: Record "FA Posting Type";
+    begin
+        // Delete FA Posting Types to simulate a fresh database state where types don't exist
+        // The fix ensures CreateTypes() is called on request page open to create them
+        FAPostingType.DeleteAll();
+    end;
+
+    local procedure CreateFixedAssetWithAcquisitionDate(var FixedAsset: Record "Fixed Asset"; var FADepreciationBook: Record "FA Depreciation Book"; var DepreciationBook: Record "Depreciation Book"; AcquisitionDate: Date)
+    var
+        FASetup: Record "FA Setup";
+    begin
+        // Create depreciation book
+        LibraryFixedAsset.CreateDepreciationBook(DepreciationBook);
+
+        // Set as default depreciation book
+        if FASetup.Get() then begin
+            FASetup."Default Depr. Book" := DepreciationBook.Code;
+            FASetup.Modify();
+        end else begin
+            FASetup.Init();
+            FASetup."Default Depr. Book" := DepreciationBook.Code;
+            FASetup.Insert();
+        end;
+
+        // Create fixed asset
+        LibraryFixedAsset.CreateFixedAsset(FixedAsset);
+
+        // Create FA Depreciation Book with acquisition date
+        LibraryFixedAsset.CreateFADepreciationBook(FADepreciationBook, FixedAsset."No.", DepreciationBook.Code);
+        FADepreciationBook."Acquisition Date" := AcquisitionDate;
+        FADepreciationBook."Depreciation Starting Date" := AcquisitionDate;
+        FADepreciationBook.Modify();
+    end;
+
+    [RequestPageHandler]
+    procedure EXRFixedAssetAnalysisExcelHandler(var EXRFixedAssetAnalysisExcel: TestRequestPage "EXR Fixed Asset Analysis Excel")
+    begin
+        EXRFixedAssetAnalysisExcel.StartingDateField.Value := Format(CalcDate('<-1M>', WorkDate()));
+        EXRFixedAssetAnalysisExcel.EndingDateField.Value := Format(WorkDate());
+        EXRFixedAssetAnalysisExcel.OK().Invoke();
+    end;
+}

