@@ -0,0 +1,156 @@
+codeunit 135302 "Item Charge Return Order Tests"
+{
+    // [FEATURE] [Item Charge] [Sales Return Order] [Default Quantity to Ship]
+    // Tests for Item Charge Assignment on Sales Return Order when "Default Quantity to Ship" is "Blank"
+
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+    end;
+
+    var
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryRandom: Codeunit "Library - Random";
+        LibraryVariableStorage: Codeunit "Library - Variable Storage";
+        LibrarySetupStorage: Codeunit "Library - Setup Storage";
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        Assert: Codeunit Assert;
+        isInitialized: Boolean;
+        OptionString: Option PostedReturnReceipt,PostedInvoices,PostedShipments,PostedCrMemo;
+
+    [Test]
+    [HandlerFunctions('PostedSalesDocumentLinesHandler')]
+    [Scope('OnPrem')]
+    procedure GetPostedDocLinesToReverseWithItemChargeWhenDefaultQtyToShipBlank()
+    var
+        SalesReceivablesSetup: Record "Sales & Receivables Setup";
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        SalesLineItemCharge: Record "Sales Line";
+        SalesReturnHeader: Record "Sales Header";
+        SalesReturnLine: Record "Sales Line";
+        ItemChargeAssignmentSales: Record "Item Charge Assignment (Sales)";
+        Item: Record Item;
+        ItemCharge: Record "Item Charge";
+        Customer: Record Customer;
+        Quantity: Decimal;
+    begin
+        // [SCENARIO] Item Charge can be pulled into Sales Return Order using "Get Posted Document Lines to Reverse" 
+        // when "Default Quantity to Ship" is set to Blank on Sales & Receivables Setup.
+        // [GIVEN] "Default Quantity to Ship" is set to "Blank" in Sales & Receivables Setup
+        Initialize();
+        UpdateDefaultQtyToShip(SalesReceivablesSetup."Default Quantity to Ship"::Blank);
+
+        // [GIVEN] Sales Order with Item (Qty: 25) and Item Charge (Qty: 25)
+        Quantity := LibraryRandom.RandIntInRange(10, 25);
+        LibrarySales.CreateCustomer(Customer);
+        LibraryInventory.CreateItem(Item);
+        LibraryInventory.CreateItemCharge(ItemCharge);
+
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Order, Customer."No.");
+
+        // Create Item line
+        LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::Item, Item."No.", Quantity);
+        SalesLine.Validate("Unit Price", LibraryRandom.RandDec(100, 2));
+        SalesLine.Validate("Qty. to Ship", Quantity);
+        SalesLine.Validate("Qty. to Invoice", Quantity);
+        SalesLine.Modify(true);
+
+        // Create Item Charge line
+        LibrarySales.CreateSalesLine(SalesLineItemCharge, SalesHeader, SalesLineItemCharge.Type::"Charge (Item)", ItemCharge."No.", Quantity);
+        SalesLineItemCharge.Validate("Unit Price", LibraryRandom.RandDec(100, 2));
+        SalesLineItemCharge.Validate("Qty. to Ship", Quantity);
+        SalesLineItemCharge.Validate("Qty. to Invoice", Quantity);
+        SalesLineItemCharge.Modify(true);
+
+        // [GIVEN] Item Charge Assignment carried out for the item line
+        CreateItemChargeAssignmentForSalesLine(ItemChargeAssignmentSales, SalesLineItemCharge, SalesLine);
+
+        // [GIVEN] Sales Order is posted (Ship and Invoice)
+        LibrarySales.PostSalesDocument(SalesHeader, true, true);
+
+        // [GIVEN] Sales Return Order is created for the same customer
+        LibrarySales.CreateSalesHeader(SalesReturnHeader, SalesReturnHeader."Document Type"::"Return Order", Customer."No.");
+
+        // [WHEN] "Get Posted Document Lines to Reverse" is invoked with both lines (Item and Charge Item) selected
+        LibraryVariableStorage.Enqueue(OptionString::PostedInvoices);
+        SalesReturnHeader.GetPstdDocLinesToReverse();
+
+        // [THEN] Both Item and Item Charge lines should be copied to the Sales Return Order without error
+        SalesReturnLine.SetRange("Document Type", SalesReturnHeader."Document Type");
+        SalesReturnLine.SetRange("Document No.", SalesReturnHeader."No.");
+        SalesReturnLine.SetRange(Type, SalesReturnLine.Type::Item);
+        Assert.RecordIsNotEmpty(SalesReturnLine);
+
+        SalesReturnLine.SetRange(Type, SalesReturnLine.Type::"Charge (Item)");
+        Assert.RecordIsNotEmpty(SalesReturnLine);
+    end;
+
+    local procedure Initialize()
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"Item Charge Return Order Tests");
+        LibraryVariableStorage.Clear();
+        LibrarySetupStorage.Restore();
+
+        if isInitialized then
+            exit;
+
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"Item Charge Return Order Tests");
+
+        LibrarySetupStorage.Save(Database::"Sales & Receivables Setup");
+
+        isInitialized := true;
+        Commit();
+
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"Item Charge Return Order Tests");
+    end;
+
+    local procedure UpdateDefaultQtyToShip(NewDefaultQtyToShip: Option)
+    var
+        SalesReceivablesSetup: Record "Sales & Receivables Setup";
+    begin
+        SalesReceivablesSetup.Get();
+        SalesReceivablesSetup.Validate("Default Quantity to Ship", NewDefaultQtyToShip);
+        SalesReceivablesSetup.Modify(true);
+    end;
+
+    local procedure CreateItemChargeAssignmentForSalesLine(var ItemChargeAssignmentSales: Record "Item Charge Assignment (Sales)"; SalesLineItemCharge: Record "Sales Line"; SalesLineItem: Record "Sales Line")
+    begin
+        ItemChargeAssignmentSales.Init();
+        ItemChargeAssignmentSales."Document Type" := SalesLineItemCharge."Document Type";
+        ItemChargeAssignmentSales."Document No." := SalesLineItemCharge."Document No.";
+        ItemChargeAssignmentSales."Document Line No." := SalesLineItemCharge."Line No.";
+        ItemChargeAssignmentSales."Item Charge No." := SalesLineItemCharge."No.";
+        ItemChargeAssignmentSales."Line No." := 10000;
+        ItemChargeAssignmentSales."Item No." := SalesLineItem."No.";
+        ItemChargeAssignmentSales."Unit Cost" := SalesLineItemCharge."Unit Price";
+        ItemChargeAssignmentSales."Applies-to Doc. Type" := ItemChargeAssignmentSales."Applies-to Doc. Type"::Order;
+        ItemChargeAssignmentSales."Applies-to Doc. No." := SalesLineItem."Document No.";
+        ItemChargeAssignmentSales."Applies-to Doc. Line No." := SalesLineItem."Line No.";
+        ItemChargeAssignmentSales."Applies-to Doc. Line Amount" := SalesLineItem."Line Amount";
+        ItemChargeAssignmentSales.Validate("Qty. to Assign", SalesLineItemCharge.Quantity);
+        ItemChargeAssignmentSales.Insert(true);
+    end;
+
+    [ModalPageHandler]
+    [Scope('OnPrem')]
+    procedure PostedSalesDocumentLinesHandler(var PostedSalesDocumentLines: TestPage "Posted Sales Document Lines")
+    var
+        DocumentType: Option "Posted Shipments","Posted Invoices","Posted Return Receipts","Posted Cr. Memos";
+    begin
+        case LibraryVariableStorage.DequeueInteger() of
+            OptionString::PostedReturnReceipt:
+                PostedSalesDocumentLines.PostedShipmentsBtn.SetValue(Format(DocumentType::"Posted Return Receipts"));
+            OptionString::PostedInvoices:
+                PostedSalesDocumentLines.PostedShipmentsBtn.SetValue(Format(DocumentType::"Posted Invoices"));
+            OptionString::PostedShipments:
+                PostedSalesDocumentLines.PostedShipmentsBtn.SetValue(Format(DocumentType::"Posted Shipments"));
+            OptionString::PostedCrMemo:
+                PostedSalesDocumentLines.PostedShipmentsBtn.SetValue(Format(DocumentType::"Posted Cr. Memos"));
+        end;
+        PostedSalesDocumentLines.OK().Invoke();
+    end;
+}

