+        SalesQty: Decimal;
+        PurchQty: Decimal;
+        SurplusQty: Decimal;
+        InitialReservationCount: Integer;
+    begin
+        // [SCENARIO] When recalculating an item in a requisition worksheet with no planning results,
+        // the system should not create wrong surplus entries in the reservation table.
+        // Bug fix: After carrying out action message from requisition worksheet with item tracking,
+        // replanning should not create duplicate surplus reservation entries.
+
+        // [GIVEN] Create Item with Lot Tracking and Lot-for-Lot Reordering Policy
+        Initialize();
+        CreateLotForLotItemWithLotTracking(Item);
+        LotNo := LibraryUtility.GenerateGUID();
+
+        // [GIVEN] Create a Sales Order to generate demand
+        SalesQty := 100;
+        LibrarySales.CreateSalesDocumentWithItem(
+            SalesHeader, SalesLine, SalesHeader."Document Type"::Order, '', Item."No.", SalesQty, '', WorkDate());
+
+        // [GIVEN] Calculate Plan in Requisition Worksheet
+        CalculatePlanForRequisitionWorksheet(RequisitionWkshName, Item, WorkDate(), WorkDate());
+
+        // [GIVEN] Find the requisition line and modify it
+        SelectRequisitionLine(RequisitionLine, Item."No.");
+        
+        // [GIVEN] Add a vendor to the requisition line
+        LibraryPurchase.CreateVendor(Vendor);
+        RequisitionLine.Validate("Vendor No.", Vendor."No.");
+        
+        // [GIVEN] Change quantity from 100 to 150 (add surplus of 50)
+        PurchQty := 150;
+        SurplusQty := PurchQty - SalesQty; // 50 surplus
+        RequisitionLine.Validate(Quantity, PurchQty);
+        
+        // [GIVEN] Set Planning Flexibility to None so replanning won't suggest changes
+        RequisitionLine.Validate("Planning Flexibility", RequisitionLine."Planning Flexibility"::None);
+        RequisitionLine.Modify(true);
+
+        // [GIVEN] Add item tracking (Lot No.) to the requisition line
+        CreateReqLineItemTracking(RequisitionLine, LotNo, PurchQty);
+
+        // [GIVEN] Accept and Carry Out Action Message - this creates a Purchase Order
+        RequisitionLine.Validate("Accept Action Message", true);
+        RequisitionLine.Modify(true);
+        LibraryPlanning.CarryOutReqWksh(RequisitionLine, WorkDate(), WorkDate(), WorkDate(), WorkDate(), '');
+
+        // [GIVEN] Find the created Purchase Line
+        FindPurchaseLine(PurchaseLine, Item."No.");
+        PurchaseLine.TestField(Quantity, PurchQty);
+
+        // [GIVEN] Count initial reservation entries for the purchase line
+        ReservationEntry.SetSourceFilter(
+            Database::"Purchase Line",
+            PurchaseLine."Document Type".AsInteger(),
+            PurchaseLine."Document No.",
+            PurchaseLine."Line No.",
+            true);
+        InitialReservationCount := ReservationEntry.Count();
+
+        // [WHEN] Calculate Plan for Requisition Worksheet again (replanning)
+        // Since Planning Flexibility = None, no new requisition lines should be created
+        LibraryPlanning.CalculatePlanForReqWksh(
+            Item, RequisitionWkshName."Worksheet Template Name", RequisitionWkshName.Name, WorkDate(), WorkDate());
+
+        // [THEN] No new requisition lines should be created (because Planning Flexibility = None)
+        RequisitionLine.Reset();
+        RequisitionLine.SetRange("Worksheet Template Name", RequisitionWkshName."Worksheet Template Name");
+        RequisitionLine.SetRange("Journal Batch Name", RequisitionWkshName.Name);
+        RequisitionLine.SetRange("No.", Item."No.");
+        Assert.IsTrue(RequisitionLine.IsEmpty(), 'No requisition lines should exist after replanning with Planning Flexibility = None');
+
+        // [THEN] Verify no duplicate surplus reservation entries were created for the Purchase Line
+        ReservationEntry.Reset();
+        ReservationEntry.SetSourceFilter(
+            Database::"Purchase Line",
+            PurchaseLine."Document Type".AsInteger(),
+            PurchaseLine."Document No.",
+            PurchaseLine."Line No.",
+            true);
+        
+        Assert.AreEqual(
+            InitialReservationCount, 
+            ReservationEntry.Count(), 
+            'Replanning should not create additional reservation entries for the purchase line');
+
+        // [THEN] Verify the total quantity in surplus reservation entries matches expected surplus
+        ReservationEntry.SetRange("Reservation Status", ReservationEntry."Reservation Status"::Surplus);
+        ReservationEntry.CalcSums("Quantity (Base)");
+        Assert.AreEqual(
+            SurplusQty, 
+            ReservationEntry."Quantity (Base)", 
+            'Total surplus quantity in reservation entries should match the expected surplus');
+
+        // [THEN] Verify no prospect entries exist (they should have been converted to surplus)
+        ReservationEntry.Reset();
+        ReservationEntry.SetSourceFilter(
+            Database::"Purchase Line",
+            PurchaseLine."Document Type".AsInteger(),
+            PurchaseLine."Document No.",
+            PurchaseLine."Line No.",
+            true);
+        ReservationEntry.SetRange("Reservation Status", ReservationEntry."Reservation Status"::Prospect);
+        Assert.IsTrue(
+            ReservationEntry.IsEmpty(), 
+            'No prospect reservation entries should exist for the purchase line after carry out');
+    end;
+
+    local procedure Initialize()
+    var
+        AllProfile: Record "All Profile";
+        ReservationEntry: Record "Reservation Entry";
+        RequisitionLine: Record "Requisition Line";
+        RequisitionWkshName: Record "Requisition Wksh. Name";
+        ConfPersonalizationMgt: Codeunit "Conf./Personalization Mgt.";
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"SCM Plan-Req.Wksht Item Track");
+        ReservationEntry.DeleteAll();
+        RequisitionLine.DeleteAll();
+        RequisitionWkshName.DeleteAll();
+        LibrarySetupStorage.Restore();
+
+        LibraryApplicationArea.EnableEssentialSetup();
+
+        // Lazy Setup.
+        if isInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"SCM Plan-Req.Wksht Item Track");
+
+        AllProfile.SetRange("Profile ID", 'ORDER PROCESSOR');
+        AllProfile.FindFirst();
+        ConfPersonalizationMgt.SetCurrentProfile(AllProfile);
+
+        LibraryERMCountryData.UpdateGeneralLedgerSetup();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        LibraryERMCountryData.UpdateSalesReceivablesSetup();
+        LibraryERMCountryData.CreateVATData();
+        NoSeriesSetup();
+
+        LibrarySetupStorage.SaveManufacturingSetup();
+        LibrarySetupStorage.SaveSalesSetup();
+        LibrarySetupStorage.SaveInventorySetup();
+
+        isInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"SCM Plan-Req.Wksht Item Track");
+    end;
+
+    local procedure NoSeriesSetup()
+    var
+        PurchasesPayablesSetup: Record "Purchases & Payables Setup";
+        SalesReceivablesSetup: Record "Sales & Receivables Setup";
+    begin
+        PurchasesPayablesSetup.Get();
+        PurchasesPayablesSetup.Validate("Order Nos.", LibraryUtility.GetGlobalNoSeriesCode());
+        PurchasesPayablesSetup.Modify(true);
+
+        SalesReceivablesSetup.Get();
+        SalesReceivablesSetup.Validate("Order Nos.", LibraryUtility.GetGlobalNoSeriesCode());
+        SalesReceivablesSetup.Validate("Blanket Order Nos.", LibraryUtility.GetGlobalNoSeriesCode());
+        SalesReceivablesSetup.Validate("Posted Shipment Nos.", LibraryUtility.GetGlobalNoSeriesCode());
+        SalesReceivablesSetup.Validate("Posted Invoice Nos.", LibraryUtility.GetGlobalNoSeriesCode());
+        SalesReceivablesSetup.Modify(true);
