+    local procedure CreateReqLineItemTracking(RequisitionLine: Record "Requisition Line"; LotNo: Code[50]; Quantity: Decimal)
+    var
+        ReservationEntry: Record "Reservation Entry";
+    begin
+        LibraryItemTracking.CreateReqWkshItemTracking(ReservationEntry, RequisitionLine, '', LotNo, Quantity);
+    end;
+
+    local procedure FindPurchaseLine(var PurchaseLine: Record "Purchase Line"; ItemNo: Code[20])
+    begin
