+        FinanceChargeMemoPage.SuggestFinChargeMemoLines.Invoke();
+        FinanceChargeMemoPage.Close();
+
+        // [GIVEN] The finance charge memo is changed to use the alternative posting group
+        FinanceChargeMemoHeader.Get(FinanceChargeMemoHeader."No.");
+        FinanceChargeMemoHeader.Validate("Customer Posting Group", AltCustomerPostingGroup.Code);
+        FinanceChargeMemoHeader.Modify(true);
