+        // [THEN] G/L entries are posted to the Receivables Account of the alternative posting group
+        GLEntry.SetRange("Document Type", GLEntry."Document Type"::"Finance Charge Memo");
+        GLEntry.SetRange("Document No.", IssuedFinChargeMemoHeader."No.");
+        GLEntry.SetRange("G/L Account No.", AltCustomerPostingGroup."Receivables Account");
