+codeunit 134980 "Reminder Level Comm. Test"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+    end;
+
+    var
+        LibraryERM: Codeunit "Library - ERM";
+        LibraryVariableStorage: Codeunit "Library - Variable Storage";
+        Assert: Codeunit Assert;
+        IsInitialized: Boolean;
+
+    local procedure Initialize()
+    begin
+        LibraryVariableStorage.Clear();
+
+        if IsInitialized then
+            exit;
+
+        IsInitialized := true;
+        Commit();
+    end;
+
+    [Test]
+    [HandlerFunctions('ConfirmHandlerNo,LanguagesModalPageHandler')]
+    procedure AddTextForLanguageWithoutExistingAttachmentText()
+    var
+        ReminderTerms: Record "Reminder Terms";
+        ReminderLevel: Record "Reminder Level";
+        ReminderAttachmentText: Record "Reminder Attachment Text";
+        ReminderEmailText: Record "Reminder Email Text";
+        ReminderLevelCommunication: TestPage "Reminder Level Communication";
+        LanguageCode: Code[10];
+    begin
+        // [FEATURE] [Reminder] [Communication]
+        // [SCENARIO] When adding text for language on Reminder Level Communication page without existing attachment texts,
+        // the system should not throw error "A reminder attachment text cannot be created without an ID"
+
+        // Bug repro steps:
+        // 1. Create Reminder Terms with a Reminder Level
+        // 2. Open Reminder Level Communication page
+        // 3. Say No to the prompts asking to create attachment/email texts
+        // 4. Click "Add text for language..." action
+        // 5. Say No to the prompts again
+        // 6. Select a language
+        // Expected: No error
+        // Actual (before fix): Error "A reminder attachment text cannot be created without an ID"
+        Initialize();
+
+        // [GIVEN] Create Reminder Terms with one Reminder Level (no attachment text or email text configured)
+        LibraryERM.CreateReminderTerms(ReminderTerms);
+        LibraryERM.CreateReminderLevel(ReminderLevel, ReminderTerms.Code);
+
+        // Verify that Reminder Level has no attachment text configured
+        Assert.IsTrue(IsNullGuid(ReminderLevel."Reminder Attachment Text"), 'Reminder Level should have no attachment text initially');
+        Assert.IsTrue(IsNullGuid(ReminderLevel."Reminder Email Text"), 'Reminder Level should have no email text initially');
+
+        // [GIVEN] Get a language code to use for the test
+        LanguageCode := LibraryERM.GetAnyLanguageDifferentFromCurrent();
+        LibraryVariableStorage.Enqueue(LanguageCode);
+
+        // [WHEN] Open Reminder Level Communication page (answer No to all confirmation dialogs)
+        // and invoke "Add text for language..." action, selecting the language
+        ReminderLevelCommunication.OpenEdit();
+        ReminderLevelCommunication.GoToRecord(ReminderLevel);
+        ReminderLevelCommunication."Add New Language".Invoke();
+        ReminderLevelCommunication.Close();
+
+        // [THEN] No error is thrown and Reminder Attachment Text is created for the selected language
+        ReminderLevel.Get(ReminderLevel."Reminder Terms Code", ReminderLevel."No.");
+        Assert.IsFalse(IsNullGuid(ReminderLevel."Reminder Attachment Text"), 'Reminder Attachment Text ID should be set on Reminder Level after adding language');
+
+        ReminderAttachmentText.SetRange(Id, ReminderLevel."Reminder Attachment Text");
+        ReminderAttachmentText.SetRange("Language Code", LanguageCode);
+        Assert.IsTrue(ReminderAttachmentText.FindFirst(), 'Reminder Attachment Text should be created for the selected language');
+
+        // [THEN] Reminder Email Text is also created
+        Assert.IsFalse(IsNullGuid(ReminderLevel."Reminder Email Text"), 'Reminder Email Text ID should be set on Reminder Level after adding language');
+
+        ReminderEmailText.SetRange(Id, ReminderLevel."Reminder Email Text");
+        ReminderEmailText.SetRange("Language Code", LanguageCode);
+        Assert.IsTrue(ReminderEmailText.FindFirst(), 'Reminder Email Text should be created for the selected language');
+    end;
+
+    [ConfirmHandler]
+    procedure ConfirmHandlerNo(Question: Text[1024]; var Reply: Boolean)
+    begin
+        // Reply No to all confirmation dialogs (simulates user declining to create attachment/email texts initially)
+        Reply := false;
+    end;
+
+    [ModalPageHandler]
+    procedure LanguagesModalPageHandler(var Languages: TestPage Languages)
+    var
+        LanguageCode: Code[10];
+    begin
+        LanguageCode := CopyStr(LibraryVariableStorage.DequeueText(), 1, 10);
+        Languages.GoToKey(LanguageCode);
+        Languages.OK().Invoke();
+    end;
+}

