+    [Test]
+    [Scope('OnPrem')]
+    procedure MfgOvhdCostCorrectForMultipleProdOrderLines()
+    var
+        RawMaterialItem: Record Item;
+        FinishedGoodItem: Record Item;
+        ProductionBOMHeader: Record "Production BOM Header";
+        ProductionOrder: Record "Production Order";
+        ProdOrderLine: Record "Prod. Order Line";
+        MfgCostCalculationMgt: Codeunit "Mfg. Cost Calculation Mgt.";
+        ShareOfTotalCapCost: Decimal;
+        ExpMatCostSingleLine: Decimal;
+        ExpCapDirCostSingleLine: Decimal;
+        ExpSubDirCostSingleLine: Decimal;
+        ExpCapOvhdCostSingleLine: Decimal;
+        ExpMfgOvhdCostSingleLine: Decimal;
+        ExpMatCostMultiLine: Decimal;
+        ExpCapDirCostMultiLine: Decimal;
+        ExpSubDirCostMultiLine: Decimal;
+        ExpCapOvhdCostMultiLine: Decimal;
+        ExpMfgOvhdCostMultiLine: Decimal;
+        UnitCost: Decimal;
+        IndirectCostPct: Decimal;
+        TotalQty: Decimal;
+        Line1Qty: Decimal;
+        Line2Qty: Decimal;
+    begin
+        // [SCENARIO] Manufacturing overhead cost should be calculated correctly when production order has multiple lines
+        // [FEATURE] [Production Order Statistics] [Manufacturing Overhead]
+        Initialize();
+
+        // [GIVEN] Define test values
+        UnitCost := 100;
+        IndirectCostPct := 10;
+        TotalQty := 20;
+        Line1Qty := 10;
+        Line2Qty := 10;
+
+        // [GIVEN] Create raw material item with Unit Cost = 100
+        LibraryInventory.CreateItem(RawMaterialItem);
+        RawMaterialItem.Validate("Unit Cost", UnitCost);
+        RawMaterialItem.Modify(true);
+
+        // [GIVEN] Create Production BOM with raw material, Qty Per = 1
+        LibraryManufacturing.CreateCertifiedProductionBOM(ProductionBOMHeader, RawMaterialItem."No.", 1);
+
+        // [GIVEN] Create finished good item with Indirect Cost % = 10 and assign production BOM
+        LibraryInventory.CreateItem(FinishedGoodItem);
+        FinishedGoodItem.Validate("Replenishment System", FinishedGoodItem."Replenishment System"::"Prod. Order");
+        FinishedGoodItem.Validate("Production BOM No.", ProductionBOMHeader."No.");
+        FinishedGoodItem.Validate("Indirect Cost %", IndirectCostPct);
+        FinishedGoodItem.Modify(true);
+
+        // [GIVEN] Create production order with single line of Qty = 20, refresh to get expected cost
+        LibraryManufacturing.CreateProductionOrder(
+            ProductionOrder, ProductionOrder.Status::"Firm Planned",
+            ProductionOrder."Source Type"::Item, FinishedGoodItem."No.", TotalQty);
+        LibraryManufacturing.RefreshProdOrder(ProductionOrder, false, true, true, true, false);
+
+        // [GIVEN] Calculate expected costs for single line
+        ProdOrderLine.SetRange(Status, ProductionOrder.Status);
+        ProdOrderLine.SetRange("Prod. Order No.", ProductionOrder."No.");
+        ProdOrderLine.FindFirst();
+        MfgCostCalculationMgt.CalcShareOfTotalCapCost(ProdOrderLine, ShareOfTotalCapCost);
+        MfgCostCalculationMgt.CalcProdOrderLineExpCost(
+            ProdOrderLine, ShareOfTotalCapCost,
+            ExpMatCostSingleLine, ExpCapDirCostSingleLine, ExpSubDirCostSingleLine,
+            ExpCapOvhdCostSingleLine, ExpMfgOvhdCostSingleLine);
+
+        // [WHEN] Create another production order with two lines (Qty 10 each = total 20), and calculate expected costs
+        LibraryManufacturing.CreateProductionOrder(
+            ProductionOrder, ProductionOrder.Status::"Firm Planned",
+            ProductionOrder."Source Type"::Item, FinishedGoodItem."No.", 0);
+
+        // Add first line
+        LibraryManufacturing.CreateProdOrderLine(
+            ProdOrderLine, ProductionOrder.Status, ProductionOrder."No.",
+            FinishedGoodItem."No.", '', '', Line1Qty);
+
+        // Add second line
+        LibraryManufacturing.CreateProdOrderLine(
+            ProdOrderLine, ProductionOrder.Status, ProductionOrder."No.",
+            FinishedGoodItem."No.", '', '', Line2Qty);
+
+        // Refresh production order (Lines = false to keep the lines we created)
+        LibraryManufacturing.RefreshProdOrder(ProductionOrder, false, false, true, true, false);
+
+        // Calculate expected costs for both lines
+        ExpMatCostMultiLine := 0;
+        ExpCapDirCostMultiLine := 0;
+        ExpSubDirCostMultiLine := 0;
+        ExpCapOvhdCostMultiLine := 0;
+        ExpMfgOvhdCostMultiLine := 0;
+
+        ProdOrderLine.SetRange(Status, ProductionOrder.Status);
+        ProdOrderLine.SetRange("Prod. Order No.", ProductionOrder."No.");
+        ProdOrderLine.FindSet();
+        repeat
+            MfgCostCalculationMgt.CalcShareOfTotalCapCost(ProdOrderLine, ShareOfTotalCapCost);
+            MfgCostCalculationMgt.CalcProdOrderLineExpCost(
+                ProdOrderLine, ShareOfTotalCapCost,
+                ExpMatCostMultiLine, ExpCapDirCostMultiLine, ExpSubDirCostMultiLine,
+                ExpCapOvhdCostMultiLine, ExpMfgOvhdCostMultiLine);
+        until ProdOrderLine.Next() = 0;
+
+        // [THEN] Manufacturing overhead cost for two lines should equal overhead for single line with same total qty
+        // Single line: Material = 20 * 100 = 2000, Overhead = 2000 * 10% = 200
+        // Two lines (10 + 10): Material = 10*100 + 10*100 = 2000, Overhead = 1000*10% + 1000*10% = 200
+        Assert.AreEqual(ExpMfgOvhdCostSingleLine, ExpMfgOvhdCostMultiLine,
+            'Manufacturing overhead cost should be the same regardless of how lines are split');
+        Assert.AreEqual(ExpMatCostSingleLine, ExpMatCostMultiLine,
+            'Material cost should be the same regardless of how lines are split');
+    end;
+
