--- a/App/Apps/W1/AutomaticAccountCodes/test/src/AACAutoAccGroupPosting.Codeunit.al
+++ b/App/Apps/W1/AutomaticAccountCodes/test/src/AACAutoAccGroupPosting.Codeunit.al
@@ -1553,5 +1553,117 @@ codeunit 139598 "AAC Auto. Acc. Group Posting"
     begin
         Reply := false;
     end;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure PostGenJournalWithCurrencyAndAutoAccGroupRoundsAmountLCYCorrectly()
+    var
+        AutomaticAccountHeader: Record "Automatic Account Header";
+        AutomaticAccountLine: Record "Automatic Account Line";
+        GenJournalLine: Record "Gen. Journal Line";
+        GenJournalLine2: Record "Gen. Journal Line";
+        GLEntry: Record "G/L Entry";
+        GLSetup: Record "General Ledger Setup";
+        CurrencyCode: Code[10];
+        GLAccountNo1: Code[20];
+        GLAccountNo2: Code[20];
+        GLAccountNo3: Code[20];
+        DocumentNo: Code[20];
+        AmountFCY: Decimal;
+    begin
+        // [FEATURE] [Currency] [Rounding]
+        // [SCENARIO 583126] Posting General Journal with Currency and Automatic Account Group should not cause inconsistency errors due to Amount (LCY) rounding differences
+        // [GIVEN] Automatic Acc. Group "AAG" with three lines:
+        // [GIVEN]  Line1: "G/L Account No." = "ACC1", "Allocation %" = 50
+        // [GIVEN]  Line2: "G/L Account No." = "ACC2", "Allocation %" = 50
+        // [GIVEN]  Line3: "G/L Account No." = "ACC3", "Allocation %" = -100 (balance line)
+        Initialize();
+
+        GLSetup.Get();
+        GLAccountNo1 := LibraryERM.CreateGLAccountNo();
+        GLAccountNo2 := LibraryERM.CreateGLAccountNo();
+        GLAccountNo3 := LibraryERM.CreateGLAccountNo();
+
+        LibraryAAC.CreateAutomaticAccountHeader(AutomaticAccountHeader);
+        CreateAutoAccLineWithAllocation(AutomaticAccountLine, AutomaticAccountHeader."No.", GLAccountNo1, 50);
+        CreateAutoAccLineWithAllocation(AutomaticAccountLine, AutomaticAccountHeader."No.", GLAccountNo2, 50);
+        CreateAutoAccLineWithAllocation(AutomaticAccountLine, AutomaticAccountHeader."No.", GLAccountNo3, -100);
+
+        // [GIVEN] Currency "EUR" with exchange rate that causes rounding issues when splitting amounts
+        // Exchange rate: 1 EUR = 10.97223 LCY causes Amount (LCY) = 5266.67 for 480 EUR
+        // Splitting 5266.67 by 50% = 2633.335 rounded to 2633.34, sum = 5266.68 (off by 0.01)
+        CurrencyCode := CreateCurrencyWithRoundingIssueRate(WorkDate());
+
+        // [GIVEN] General Journal with Currency and two lines:
+        // [GIVEN] Line1: Amount = 480 EUR (Amount LCY causing odd split), "Automatic Account Group" = "AAG"
+        // [GIVEN] Line2: Amount = -480 EUR (balancing line)
+        AmountFCY := 480;
+        LibraryJournals.CreateGenJournalLineWithBatch(
+          GenJournalLine, GenJournalLine."Document Type"::" ",
+          GenJournalLine."Account Type"::"G/L Account", LibraryERM.CreateGLAccountNo(),
+          0);
+        GenJournalLine.Validate("Currency Code", CurrencyCode);
+        GenJournalLine.Validate(Amount, AmountFCY);
+        GenJournalLine.Validate("Bal. Account No.", '');
+        GenJournalLine.Validate("Automatic Account Group", AutomaticAccountHeader."No.");
+        GenJournalLine.Modify();
+        DocumentNo := GenJournalLine."Document No.";
+
+        LibraryERM.CreateGeneralJnlLine(
+          GenJournalLine2, GenJournalLine."Journal Template Name", GenJournalLine."Journal Batch Name",
+          GenJournalLine2."Document Type"::" ", GenJournalLine2."Account Type"::"G/L Account", LibraryERM.CreateGLAccountNo(),
+          0);
+        GenJournalLine2.Validate("Document No.", DocumentNo);
+        GenJournalLine2.Validate("Currency Code", CurrencyCode);
+        GenJournalLine2.Validate(Amount, -AmountFCY);
+        GenJournalLine2.Modify();
+
+        // [WHEN] Post General Journal
+        LibraryERM.PostGeneralJnlLine(GenJournalLine);
+
+        // [THEN] G/L Entries are created without inconsistency error
+        // [THEN] The sum of all G/L Entry amounts for the document is 0 (balanced)
+        GLEntry.SetRange("Document No.", DocumentNo);
+        GLEntry.CalcSums(Amount);
+        Assert.AreEqual(0, GLEntry.Amount, 'G/L Entry amounts should be balanced after posting with currency and auto acc. group');
+
+        // [THEN] G/L Entries for allocation accounts also sum to 0
+        GLEntry.SetFilter("G/L Account No.", '%1|%2|%3', GLAccountNo1, GLAccountNo2, GLAccountNo3);
+        GLEntry.CalcSums(Amount);
+        Assert.AreEqual(0, GLEntry.Amount, 'Automatic Account allocation entries should be balanced');
+    end;
+
+    local procedure CreateAutoAccLineWithAllocation(var AutomaticAccountLine: Record "Automatic Account Line"; AutomaticAccNo: Code[10]; GLAccountNo: Code[20]; AllocationPct: Decimal)
+    var
+        RecRef: RecordRef;
+    begin
+        AutomaticAccountLine.Init();
+        AutomaticAccountLine.Validate("Automatic Acc. No.", AutomaticAccNo);
+        RecRef.GetTable(AutomaticAccountLine);
+        AutomaticAccountLine.Validate("Line No.", LibraryUtility.GetNewLineNo(RecRef, AutomaticAccountLine.FieldNo("Line No.")));
+        AutomaticAccountLine.Validate("G/L Account No.", GLAccountNo);
+        AutomaticAccountLine.Validate("Allocation %", AllocationPct);
+        AutomaticAccountLine.Insert(true);
+    end;
+
+    local procedure CreateCurrencyWithRoundingIssueRate(PostingDate: Date): Code[10]
+    var
+        Currency: Record Currency;
+        CurrencyExchangeRate: Record "Currency Exchange Rate";
+    begin
+        // Create currency with exchange rate that causes rounding issues
+        // 1 EUR = 10.97223 LCY (inverted: ~0.09114)
+        // This rate causes 480 EUR = 5266.6704 LCY, rounded to 5266.67
+        // Splitting 5266.67 by 50% = 2633.335 which rounds to 2633.34
+        // Sum of 2 x 2633.34 = 5266.68, which is 0.01 more than original 5266.67
+        LibraryERM.CreateCurrency(Currency);
+        LibraryERM.CreateExchRate(CurrencyExchangeRate, Currency.Code, PostingDate);
+        CurrencyExchangeRate.Validate("Exchange Rate Amount", 1);
+        CurrencyExchangeRate.Validate("Adjustment Exch. Rate Amount", 1);
+        CurrencyExchangeRate.Validate("Relational Exch. Rate Amount", 10.97223);
+        CurrencyExchangeRate.Validate("Relational Adjmt Exch Rate Amt", 10.97223);
+        CurrencyExchangeRate.Modify(true);
+        exit(Currency.Code);
+    end;
 }

