+    [Test]
+    [Scope('OnPrem')]
+    procedure ProdOrderComponentQtyPerWithUOMQtyRoundingPrecisionOne()
+    var
+        ComponentItem: Record Item;
+        FinishedItem: Record Item;
+        ProductionBOMHeader: Record "Production BOM Header";
+        ProductionBOMLine: Record "Production BOM Line";
+        ProductionOrder: Record "Production Order";
+        ProdOrderComponent: Record "Prod. Order Component";
+        ItemUnitOfMeasure: Record "Item Unit of Measure";
+        QtyPerInBOM: Decimal;
+    begin
+        // [FEATURE] [Production Order] [Production BOM] [Qty. Rounding Precision]
+        // [SCENARIO] When a component's Item UOM has 'Quantity Rounding Precision' = 1 and the BOM has a fractional 'Quantity Per',
+        // the Prod. Order Component should preserve the 'Quantity Per' value using Item's Rounding Precision instead.
+        Initialize();
+
+        // [GIVEN] Create a component item with Replenishment System = Purchase and Rounding Precision = 0.01
+        LibraryInventory.CreateItem(ComponentItem);
+        ComponentItem.Validate("Replenishment System", ComponentItem."Replenishment System"::Purchase);
+        ComponentItem.Validate("Rounding Precision", 0.01);
+        ComponentItem.Modify(true);
+
+        // [GIVEN] Set the component's Item UOM 'Qty. Rounding Precision' = 1 (integer rounding)
+        ItemUnitOfMeasure.Get(ComponentItem."No.", ComponentItem."Base Unit of Measure");
+        ItemUnitOfMeasure.Validate("Qty. Rounding Precision", 1);
+        ItemUnitOfMeasure.Modify(true);
+
+        // [GIVEN] Create a finished item with Replenishment System = Prod. Order and Rounding Precision = 1
+        LibraryInventory.CreateItem(FinishedItem);
+        FinishedItem.Validate("Replenishment System", FinishedItem."Replenishment System"::"Prod. Order");
+        FinishedItem.Validate("Rounding Precision", 1);
+        FinishedItem.Modify(true);
+
+        // [GIVEN] Create a Production BOM with the component having a fractional Quantity Per = 0.09
+        QtyPerInBOM := 0.09;
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader, FinishedItem."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(
+          ProductionBOMHeader, ProductionBOMLine, '', ProductionBOMLine.Type::Item, ComponentItem."No.", QtyPerInBOM);
+        ProductionBOMHeader.Validate(Status, ProductionBOMHeader.Status::Certified);
+        ProductionBOMHeader.Modify(true);
+
+        // [GIVEN] Assign the Production BOM to the finished item
+        FinishedItem.Validate("Production BOM No.", ProductionBOMHeader."No.");
+        FinishedItem.Modify(true);
+
+        // [WHEN] Create and refresh a Released Production Order for the finished item with Quantity = 1
+        LibraryManufacturing.CreateProductionOrder(
+          ProductionOrder, ProductionOrder.Status::Released, ProductionOrder."Source Type"::Item, FinishedItem."No.", 1);
+        LibraryManufacturing.RefreshProdOrder(ProductionOrder, false, true, true, true, false);
+
+        // [THEN] The Prod. Order Component should have 'Quantity Per' = 0.09 (not 0)
+        ProdOrderComponent.SetRange(Status, ProductionOrder.Status);
+        ProdOrderComponent.SetRange("Prod. Order No.", ProductionOrder."No.");
+        ProdOrderComponent.SetRange("Item No.", ComponentItem."No.");
+        ProdOrderComponent.FindFirst();
+        Assert.AreEqual(QtyPerInBOM, ProdOrderComponent."Quantity per", 'Quantity per should not be rounded to 0 due to UOM rounding precision');
+
+        // [THEN] The Expected Quantity should also be 0.09
+        Assert.AreEqual(QtyPerInBOM, ProdOrderComponent."Expected Quantity", 'Expected Quantity should match the BOM Quantity Per');
+    end;
