+        CustLedgerEntry: Record "Cust. Ledger Entry";
+        ReminderFinChargeEntry: Record "Reminder/Fin. Charge Entry";
+        ReminderHeader: Record "Reminder Header";
+        WeekDateFormula: DateFormula;
+        InvoicePostingDate: Date;
+        ReminderPostingDate: Date;
+        OriginalDueDate: Date;
+        EarlierDueDate: Date;
+        InvoiceDocNo: Code[20];
+    begin
+        // [FEATURE] [Reminder] [Due Date]
+        // [SCENARIO] When customer ledger entry due date is changed to an earlier date, 
+        // the Reminder/Fin. Charge Entry due date should also be updated.
+        Initialize();
+        Evaluate(WeekDateFormula, '<1W>');
+
+        // [GIVEN] Customer with payment and reminder terms
+        CreateCustomerWithPaymentAndReminderTerms(Customer, WeekDateFormula);
+
+        // [GIVEN] Posted sales invoice with due date 
+        InvoicePostingDate := WorkDate();
+        InvoiceDocNo := PostSalesInvoice(Customer."No.", InvoicePostingDate);
+
+        // [GIVEN] Issued reminder for the invoice
+        ReminderPostingDate := CalcDate('<3W>', InvoicePostingDate);
+        CreateReminderForDate(ReminderHeader, Customer."No.", ReminderPostingDate);
+        REPORT.RunModal(REPORT::"Issue Reminders", false, true, ReminderHeader);
+
+        // [GIVEN] Find the customer ledger entry and reminder/fin. charge entry
+        CustLedgerEntry.SetRange("Customer No.", Customer."No.");
+        CustLedgerEntry.SetRange("Document No.", InvoiceDocNo);
+        CustLedgerEntry.FindFirst();
+        OriginalDueDate := CustLedgerEntry."Due Date";
