+        ReminderFinChargeEntry.SetRange(Type, ReminderFinChargeEntry.Type::Reminder);
+        ReminderFinChargeEntry.FindLast();
+
+        // [WHEN] Change customer ledger entry due date to an EARLIER date than the reminder entry due date
+        EarlierDueDate := ReminderFinChargeEntry."Due Date" - 7;
