+    [Test]
+    [Scope('OnPrem')]
+    procedure CarryOutActionMessageRespectsActionMessageFilter()
+    var
+        Item: Record Item;
+        PurchaseHeader: Record "Purchase Header";
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        RequisitionLine: Record "Requisition Line";
+        CarryOutActionMsgPlan: Report "Carry Out Action Msg. - Plan.";
+        OriginalPurchaseOrderNo: Code[20];
+        SalesOrderDate: Date;
+        Quantity: Decimal;
+        PurchOrderCountBefore: Integer;
+    begin
+        // [SCENARIO] When filtering by Action Message in the Planning Worksheet and carrying out action messages,
+        // only the filtered lines should be processed. Non-filtered lines should remain in the worksheet.
+        Initialize();
+
+        // [GIVEN] Create an item with Order reordering policy and Purchase replenishment system.
+        CreateItem(Item, Item."Reordering Policy"::Order, Item."Replenishment System"::Purchase);
+
+        // [GIVEN] Create a purchase order for the item with the current work date.
+        Quantity := LibraryRandom.RandIntInRange(5, 10);
+        CreatePurchaseOrder(PurchaseHeader, Item."No.", WorkDate(), Quantity);
+        OriginalPurchaseOrderNo := PurchaseHeader."No.";
+
+        // [GIVEN] Create a sales order for the item with a future shipment date (will generate a "New" action message).
+        SalesOrderDate := CalcDate('<+1M>', WorkDate());
+        CreateSalesOrder(SalesHeader, SalesLine, Item."No.", Quantity);
+        SalesLine.Validate("Shipment Date", SalesOrderDate);
+        SalesLine.Modify(true);
+
+        // [GIVEN] Count purchase orders before carry out.
+        PurchaseHeader.Reset();
+        PurchaseHeader.SetRange("Document Type", PurchaseHeader."Document Type"::Order);
+        PurchOrderCountBefore := PurchaseHeader.Count();
+
+        // [GIVEN] Calculate regenerative plan - this generates two requisition lines:
+        // - "Cancel" action for the existing purchase order (dated before new demand)
+        // - "New" action for the sales order demand
+        LibraryPlanning.CalcRegenPlanForPlanWksh(Item, WorkDate(), CalcDate('<+2M>', WorkDate()));
+
+        // [GIVEN] Verify that two lines were created with different action messages.
+        RequisitionLine.SetRange(Type, RequisitionLine.Type::Item);
+        RequisitionLine.SetRange("No.", Item."No.");
+        Assert.AreEqual(2, RequisitionLine.Count, 'Expected two requisition lines after planning');
+
+        // [GIVEN] Find and accept only the "Cancel" action message line.
+        RequisitionLine.SetRange("Action Message", RequisitionLine."Action Message"::Cancel);
+        RequisitionLine.FindFirst();
+        RequisitionLine.Validate("Accept Action Message", true);
+        RequisitionLine.Modify(true);
+
+        // [WHEN] Carry out action message with Action Message filter = Cancel.
+        Commit();
+        CarryOutActionMsgPlan.InitializeRequest(0, 1, 0, 0); // Only make Purchase Orders
+        RequisitionLine.Reset();
+        RequisitionLine.SetRange(Type, RequisitionLine.Type::Item);
+        RequisitionLine.SetRange("No.", Item."No.");
+        RequisitionLine.SetRange("Action Message", RequisitionLine."Action Message"::Cancel);
+        CarryOutActionMsgPlan.SetReqWkshLine(RequisitionLine);
+        CarryOutActionMsgPlan.SetTableView(RequisitionLine);
+        CarryOutActionMsgPlan.UseRequestPage(false);
+        CarryOutActionMsgPlan.RunModal();
+
+        // [THEN] The original purchase order should be cancelled (deleted).
+        Assert.IsFalse(PurchaseHeader.Get(PurchaseHeader."Document Type"::Order, OriginalPurchaseOrderNo), 'Original purchase order should be cancelled');
+
+        // [THEN] No new purchase orders should be created (because we only carried out Cancel action).
+        PurchaseHeader.Reset();
+        PurchaseHeader.SetRange("Document Type", PurchaseHeader."Document Type"::Order);
+        Assert.AreEqual(PurchOrderCountBefore - 1, PurchaseHeader.Count(), 'No new purchase order should be created');
+
+        // [THEN] The "New" requisition line should still exist in the planning worksheet.
+        RequisitionLine.Reset();
+        RequisitionLine.SetRange(Type, RequisitionLine.Type::Item);
+        RequisitionLine.SetRange("No.", Item."No.");
+        RequisitionLine.SetRange("Action Message", RequisitionLine."Action Message"::New);
+        Assert.RecordIsNotEmpty(RequisitionLine);
+    end;
+
     [Test]
     [HandlerFunctions('PurchaseOrderSaveAsXML')]
     [Scope('OnPrem')]

